function GwSignaturePad({ onSign }) {
  const canvasRef = useRef(null);
  const drawing = useRef(false);
  const getPos = (e, canvas) => {
    const rect = canvas.getBoundingClientRect();
    const src = e.touches ? e.touches[0] : e;
    return [(src.clientX - rect.left) * (canvas.width / rect.width), (src.clientY - rect.top) * (canvas.height / rect.height)];
  };
  const startDraw = e => { drawing.current=true; const [x,y]=getPos(e,canvasRef.current); const ctx=canvasRef.current.getContext("2d"); ctx.beginPath(); ctx.moveTo(x,y); };
  const draw = e => { if(!drawing.current) return; e.preventDefault(); const [x,y]=getPos(e,canvasRef.current); const ctx=canvasRef.current.getContext("2d"); ctx.lineWidth=2; ctx.strokeStyle="#1a1a2e"; ctx.lineTo(x,y); ctx.stroke(); };
  const endDraw = () => {
    if(!drawing.current) return;
    drawing.current=false;
    setTimeout(()=>{
      if(canvasRef.current) {
        const dataUrl = canvasRef.current.toDataURL("image/png");
        try { localStorage.setItem(sk("gsc_engineer_sig"), dataUrl); } catch(e) {}
        onSign(dataUrl);
      }
    }, 50);
  };
  const clear = () => { const c=canvasRef.current; c.getContext("2d").clearRect(0,0,c.width,c.height); onSign(null); };
  return (
    <div>
      <div style={{ border:"1.5px solid #e5e7eb", borderRadius:10, overflow:"hidden", background:"#fff" }}>
        <canvas ref={canvasRef} width={600} height={150} style={{ display:"block", width:"100%", touchAction:"none", cursor:"crosshair" }}
          onMouseDown={startDraw} onMouseMove={draw} onMouseUp={endDraw} onMouseLeave={endDraw}
          onTouchStart={startDraw} onTouchMove={draw} onTouchEnd={endDraw}/>
      </div>
      <button onClick={clear} style={{ marginTop:8, padding:"6px 18px", background:"none", border:`1.5px solid #e5e7eb`, borderRadius:8, fontSize:13, color:"#888", cursor:"pointer" }}>Clear</button>
    </div>
  );
}

