// Load any custom locations the user has added
function getCustomLocations() {
  try { return JSON.parse(localStorage.getItem("wlg_custom_locations") || "[]"); } catch { return []; }
}
function saveCustomLocation(loc) {
  const existing = getCustomLocations();
  if (!existing.includes(loc) && !LOCATIONS_DEFAULT.includes(loc)) {
    const updated = [...existing, loc].sort();
    try { localStorage.setItem("wlg_custom_locations", JSON.stringify(updated)); } catch {}
  }
}
function getAllLocations() {
  return [...LOCATIONS_DEFAULT, ...getCustomLocations().filter(c => !LOCATIONS_DEFAULT.includes(c))];
}

// Keep LOCATIONS as a dynamic getter for backward compatibility
const LOCATIONS = getAllLocations();
