function QuotesScreen({ quotes, onBack, onHome, onDelete, onConvertToInvoice }) {
  const [selected, setSelected] = useState(null);
  const [viewing, setViewing] = useState(null);
  const [confirmDelete, setConfirmDelete] = useState(null);

  if (viewing !== null) {
    const q = quotes[viewing];
    return <QuotePDFPreview quoteData={q} onClose={()=>setViewing(null)} onSave={()=>{}} />;
  }

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Quotes" onBack={onBack}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        {quotes.length===0 ? (
          <div style={{ textAlign:"center", color:"#aaa", marginTop:60, fontSize:15 }}>No quotes yet</div>
        ) : quotes.map((q,i)=>(
          <div key={i} onClick={()=>setSelected(i)}
            style={{ background:"#fff", borderRadius:10, padding:"14px 16px", marginBottom:10, boxShadow:"0 2px 8px rgba(0,0,0,0.06)", borderLeft:`4px solid ${BLUE}`, cursor:"pointer" }}>
            <div style={{ fontWeight:700, fontSize:15, color:"#222" }}>{q.quoteNo}</div>
            <div style={{ fontSize:13, color:"#888", marginTop:3 }}>{q.clientName} · {q.instAddr1||q.clientAddr1}</div>
            <div style={{ fontSize:12, color:DARK_BLUE, marginTop:3, display:"flex", justifyContent:"space-between" }}>
              <span>📝 £{(q.total||0).toFixed(2)}</span>
              <span>{q.createdAt ? new Date(q.createdAt).toLocaleDateString("en-GB") : ""}</span>
            </div>
          </div>
        ))}
      </div>
      <BottomBar onHome={onHome}/>
      {selected !== null && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.5)", display:"flex", alignItems:"flex-end", zIndex:2000 }} onClick={()=>setSelected(null)}>
          <div style={{ background:"#fff", width:"100%", borderRadius:"20px 20px 0 0", padding:24 }} onClick={e=>e.stopPropagation()}>
            <div style={{ fontWeight:700, fontSize:15, color:"#222", marginBottom:4, textAlign:"center" }}>{quotes[selected]?.quoteNo}</div>
            <div style={{ fontSize:12, color:"#aaa", textAlign:"center", marginBottom:20 }}>Choose an action</div>
            {[
              { label:"👁 Download", fn:()=>{ setViewing(selected); setSelected(null); }, color:"#222" },
              { label:"📄 Copy to Invoice", fn:()=>{ onConvertToInvoice(selected); setSelected(null); }, color:DARK_BLUE },
              { label:"🗑 Delete", fn:()=>{ setConfirmDelete(selected); setSelected(null); }, color:"#c00" },
            ].map(({label,fn,color})=>(
              <button key={label} onClick={fn}
                style={{ display:"block", width:"100%", padding:"14px 20px", marginBottom:10, borderRadius:12, border:"1px solid #e8eaf0", background:"#fafafa", fontSize:15, fontWeight:600, color, cursor:"pointer", textAlign:"left" }}>
                {label}
              </button>
            ))}
            <button onClick={()=>setSelected(null)} style={{ display:"block", width:"100%", padding:"14px 20px", borderRadius:12, border:"none", background:"#f0f0f0", fontSize:15, fontWeight:600, color:"#666", cursor:"pointer", textAlign:"center" }}>Cancel</button>
          </div>
        </div>
      )}
      {confirmDelete !== null && (
        <ConfirmDeleteModal onCancel={()=>setConfirmDelete(null)} onConfirm={()=>{ onDelete(confirmDelete); setConfirmDelete(null); }}/>
      )}
    </div>
  );
}

