// ─── Reminders Screen ─────────────────────────────────────────────────────────
function RemindersScreen({ records, onBack, onHome, engineerData, onRenew }) {
  const DAYS_AHEAD = 30;

  const now = new Date();
  const cutoff = new Date(now); cutoff.setDate(cutoff.getDate() + DAYS_AHEAD);

  function extractInfo(r) {
    let name, addr1, addr2, postcode, tel, email, dueDate, type, certRef;
    if (!r.type || r.type === "gsc") {
      const cd = r.certData || {}; const fc = r.finalChecks || {};
      dueDate = fc.inspectionDate ? new Date(fc.inspectionDate) : null;
      name = cd.clientName || cd.instName || "";
      addr1 = cd.instAddr1 || cd.clientAddr1 || "";
      addr2 = cd.instAddr2 || cd.clientAddr2 || "";
      postcode = cd.instPostcode || cd.clientPostcode || "";
      tel = cd.clientTel || cd.instTel || "";
      email = cd.clientEmail || "";
      type = "Gas Safety Certificate"; certRef = cd.certRef || "";
    } else if (r.type === "bs") {
      const sd = r.serviceData || {};
      // Try multiple sources for the service date: bsEngData.certDate, serviceData.certDate, savedAt
      const rawDate = r.bsEngData?.certDate || sd.certDate || r.savedAt || null;
      const certDate = rawDate ? new Date(rawDate) : null;
      dueDate = certDate && !isNaN(certDate) ? new Date(certDate.getFullYear()+1, certDate.getMonth(), certDate.getDate()) : null;
      name = sd.clientName || sd.instName || "";
      addr1 = sd.instAddr1 || sd.clientAddr1 || "";
      addr2 = sd.instAddr2 || sd.clientAddr2 || "";
      postcode = sd.instPostcode || sd.clientPostcode || "";
      tel = sd.clientTel || sd.instTel || "";
      email = sd.clientEmail || "";
      type = "Boiler Service"; certRef = sd.certRef || "";
    } else {
      // All new dedicated cert types (LPG, Leisure, Commercial GSC, Cool Off, GISR, Catering, GTP)
      const RENEWABLES = ["lpg_gsc","leisure_gsc","commercial_gsc","gas_install_report","catering_inspection","gas_test_purge","cooling_off"];
      if (!RENEWABLES.includes(r.type)) return null;
      const f = r.form || {};
      // Extract client/installation details — certs use different field names
      name     = f.clientAddr || f.clientName || f.instAddr || f.tradingTitle || "";
      addr1    = f.instAddr   || f.clientAddr || f.engAddr  || "";
      addr2    = f.instCity   || f.clientCity || f.engCity  || "";
      postcode = f.instPostcode || f.clientPostcode || f.engPostcode || "";
      tel      = f.clientTel  || f.instTel    || f.engTel   || "";
      email    = f.clientEmail|| f.instEmail  || "";
      certRef  = f.certRef || f.certNo || "";
      type     = r.certLabel  || r.type;
      // Due date: nextInspection if present (LPG, Leisure, Commercial GSC, GISR, Catering)
      // Cool Off and GTP don't have a renewal date — use savedAt + 1 year as fallback
      if (f.nextInspection) {
        dueDate = new Date(f.nextInspection);
      } else {
        const base = r.savedAt ? new Date(r.savedAt) : null;
        dueDate = base && !isNaN(base) ? new Date(base.getFullYear()+1, base.getMonth(), base.getDate()) : null;
      }
    }
    return { name, addr1, addr2, postcode, tel, email, dueDate, type, certRef };
  }

  // Auto: due within 30 days
  const autoReminders = [];
  // Pinned: manually added regardless of date
  const pinnedReminders = [];

  for (const r of records) {
    const info = extractInfo(r);
    if (!info) continue;
    const { name, addr1, addr2, postcode, tel, email, dueDate, type, certRef } = info;
    if (!name && !addr1) continue;
    const daysLeft = dueDate && !isNaN(dueDate) ? Math.round((dueDate - now) / (1000*60*60*24)) : null;
    const isDueSoon = dueDate && !isNaN(dueDate) && dueDate >= now && dueDate <= cutoff;
    const isPinned = r.pinnedReminder;

    if (isDueSoon) {
      autoReminders.push({ name, addr1, addr2, postcode, tel, email, dueDate, daysLeft, type, certRef, _record: r });
    } else if (isPinned) {
      pinnedReminders.push({ name, addr1, addr2, postcode, tel, email, dueDate, daysLeft, type, certRef, _record: r });
    }
  }

  autoReminders.sort((a,b) => a.dueDate - b.dueDate);
  pinnedReminders.sort((a,b) => (a.daysLeft||9999) - (b.daysLeft||9999));

  const eng = engineerData || {};
  const bizName = eng.companyName || "";
  const bizTel  = eng.companyTel  || "";
  const bizEmail= eng.companyEmail|| "";
  const bizWeb  = eng.companyWeb  || "";

  function buildHTMLEmail(r) {
    const fmtDate = r.dueDate ? r.dueDate.toLocaleDateString("en-GB") : "soon";
    const addrLines = [r.addr1, r.addr2, r.postcode].filter(Boolean);
    const subject = `Your ${r.type} is Due for Renewal`;
    const html = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f4f4f4;font-family:Arial,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f4f4f4;padding:24px 0;">
    <tr><td align="center">
      <table width="600" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.10);">

        <!-- Header with logos -->
        <tr style="background:#ffffff;border-bottom:2px solid #e0e4ee;">
          <td style="padding:20px 28px;">
            <table width="100%" cellpadding="0" cellspacing="0">
              <tr>
                <td align="left" style="width:50%;">
                  <img src="${getCompanyLogo()}" height="80" style="display:block;max-width:200px;object-fit:contain;" alt="Company Logo"/>
                </td>
                <td align="right" style="width:50%;">
                  <img src="${GAS_SAFE_LOGO}" height="80" style="display:block;margin-left:auto;max-width:120px;object-fit:contain;" alt="Gas Safe Registered"/>
                </td>
              </tr>
            </table>
          </td>
        </tr>

        <!-- Subject banner -->
        <tr style="background:#cc0000;">
          <td style="padding:16px 28px;">
            <p style="margin:0;font-size:17px;font-weight:bold;color:#ffffff;">Your ${r.type} is Due for Renewal</p>
          </td>
        </tr>

        <!-- Body -->
        <tr>
          <td style="padding:28px 28px 20px 28px;color:#222;font-size:15px;line-height:1.7;">
            <p style="margin:0 0 14px 0;">Dear ${r.name || "Customer"},</p>
            <p style="margin:0 0 14px 0;">It's been nearly 12 months since <strong>${bizName}</strong> visited your property to carry out a <strong>${r.type}</strong>.</p>
            <p style="margin:0 0 14px 0;">This is due for renewal before <strong>${fmtDate}</strong>. It is really important to keep your gas appliances regularly serviced and checked.</p>
            <p style="margin:0 0 14px 0;">We would like to arrange a time convenient with you to re-book the appointment.</p>
            <p style="margin:0 0 20px 0;">To arrange an appointment please call <strong>${bizTel}</strong>${bizEmail ? ` or reply to this email` : ""}.</p>

            ${addrLines.length ? `
            <table cellpadding="0" cellspacing="0" style="background:#f0f4ff;border-left:4px solid #1a3a8f;border-radius:4px;margin-bottom:20px;width:100%;">
              <tr><td style="padding:12px 16px;">
                <p style="margin:0 0 4px 0;font-size:12px;color:#888;text-transform:uppercase;letter-spacing:0.5px;">Property Address</p>
                <p style="margin:0;font-size:14px;color:#222;line-height:1.6;">${addrLines.join("<br/>")}</p>
              </td></tr>
            </table>` : ""}

            <p style="margin:0 0 4px 0;">Kind Regards,</p>
            <p style="margin:0;font-weight:bold;color:#1a3a8f;">${bizName}</p>
          </td>
        </tr>

        <!-- Footer -->
        <tr style="background:#f8f9fc;border-top:1px solid #e0e4ee;">
          <td style="padding:16px 28px;">
            <table width="100%" cellpadding="0" cellspacing="0">
              <tr>
                <td style="font-size:12px;color:#666;line-height:1.8;">
                  ${bizEmail ? `📧 <a href="mailto:${bizEmail}" style="color:#1a3a8f;text-decoration:none;">${bizEmail}</a><br/>` : ""}
                  📞 ${bizTel}<br/>
                  ${bizWeb ? `🌐 <a href="http://${bizWeb}" style="color:#1a3a8f;text-decoration:none;">${bizWeb}</a>` : ""}
                </td>
                <td align="right" valign="middle">
                  <img src="${GAS_SAFE_LOGO}" height="36" style="opacity:0.7;object-fit:contain;" alt="Gas Safe"/>
                </td>
              </tr>
            </table>
          </td>
        </tr>

      </table>
    </td></tr>
  </table>
</body>
</html>`;
    return { subject, html, to: r.email || "" };
  }

  function copyHTMLEmail(r) {
    const { html } = buildHTMLEmail(r);
    // Write as HTML to clipboard so it pastes as rich content in Outlook/Gmail
    const blob = new Blob([html], { type: "text/html" });
    const item = new ClipboardItem({ "text/html": blob });
    navigator.clipboard.write([item]).then(
      () => alert("✅ HTML email copied!\n\nPaste it into a new email in Outlook or Gmail — the logos and formatting will appear automatically."),
      () => {
        // Fallback: copy plain text
        const { subject } = buildHTMLEmail(r);
        const fmtDate = r.dueDate ? r.dueDate.toLocaleDateString("en-GB") : "soon";
        const addrLines = [r.addr1, r.addr2, r.postcode].filter(Boolean);
        const plain = `Dear ${r.name || "Customer"},\n\nIt's been nearly 12 months since ${bizName} visited your property to carry out a ${r.type}.\n\nThis is due for renewal before ${fmtDate}. It is really important to keep your gas appliances regularly serviced and checked.\n\nWe would like to arrange a time convenient with you to re-book the appointment.\n\nTo arrange an appointment please call ${bizTel}${bizEmail ? ` or reply to this email` : ""}.\n\nProperty Address:\n${addrLines.join(", ")}\n\nKind Regards,\n${bizName}\n${bizEmail ? `Email: ${bizEmail}\n` : ""}Tel: ${bizTel}\n${bizWeb ? `Web: ${bizWeb}` : ""}`;
        navigator.clipboard.writeText(plain).then(() => alert("✅ Email copied (plain text — your browser doesn't support rich HTML copy)."));
      }
    );
  }

  function openMailto(r) {
    const { subject, to } = buildHTMLEmail(r);
    const fmtDate = r.dueDate ? r.dueDate.toLocaleDateString("en-GB") : "soon";
    const addrLines = [r.addr1, r.addr2, r.postcode].filter(Boolean);
    const plain = `Dear ${r.name || "Customer"},\n\nIt's been nearly 12 months since ${bizName} visited your property to carry out a ${r.type}.\n\nThis is due for renewal before ${fmtDate}. It is really important to keep your gas appliances regularly serviced and checked.\n\nWe would like to arrange a time convenient with you to re-book the appointment.\n\nTo arrange an appointment please call ${bizTel}${bizEmail ? ` or reply to this email` : ""}.\n\nProperty Address:\n${addrLines.join(", ")}\n\nKind Regards,\n${bizName}\n${bizEmail ? `Email: ${bizEmail}\n` : ""}Tel: ${bizTel}\n${bizWeb ? `Web: ${bizWeb}` : ""}`;
    window.open(`mailto:${encodeURIComponent(to)}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(plain)}`, "_blank");
  }

  const urgencyColor = (days) => days === null ? "#888" : days <= 7 ? "#c00" : days <= 14 ? "#e07000" : "#1a7a3a";

  function ReminderCard({ r, i }) {
    return (
      <div key={i} style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 2px 10px rgba(0,0,0,0.07)", borderLeft:`4px solid ${urgencyColor(r.daysLeft)}` }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:6 }}>
          <div>
            <div style={{ fontWeight:700, fontSize:15, color:"#222" }}>{r.name || "Unknown"}</div>
            <div style={{ fontSize:12, color:"#666", marginTop:2 }}>{[r.addr1, r.addr2, r.postcode].filter(Boolean).join(", ")}</div>
          </div>
          <div style={{ textAlign:"right", flexShrink:0, marginLeft:8 }}>
            {r.daysLeft !== null ? (
              <>
                <div style={{ fontWeight:700, fontSize:13, color:urgencyColor(r.daysLeft) }}>{r.daysLeft} day{r.daysLeft!==1?"s":""}</div>
                <div style={{ fontSize:11, color:"#aaa" }}>remaining</div>
              </>
            ) : <div style={{ fontSize:11, color:"#aaa" }}>No due date</div>}
          </div>
        </div>
        <div style={{ display:"flex", gap:6, alignItems:"center", marginBottom:10 }}>
          <span style={{ background:`${urgencyColor(r.daysLeft)}18`, color:urgencyColor(r.daysLeft), fontSize:11, fontWeight:700, padding:"2px 8px", borderRadius:8 }}>{r.type}</span>
          {r.dueDate && <span style={{ fontSize:11, color:"#aaa" }}>Due: {r.dueDate.toLocaleDateString("en-GB")}</span>}
          {r.certRef && <span style={{ fontSize:11, color:"#aaa" }}>· {r.certRef}</span>}
        </div>
        {r.email ? (
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
            <button onClick={()=>openMailto(r)} style={{ padding:"10px 0", background:BLUE, color:"#fff", border:"none", borderRadius:8, fontWeight:700, fontSize:13, cursor:"pointer" }}>✉️ Open in Mail</button>
            <button onClick={()=>copyHTMLEmail(r)} style={{ padding:"10px 0", background:"#f5f5f5", color:BLUE, border:`2px solid ${BLUE}`, borderRadius:8, fontWeight:700, fontSize:13, cursor:"pointer" }}>📋 Copy HTML Email</button>
          </div>
        ) : (
          <button onClick={()=>copyHTMLEmail(r)} style={{ width:"100%", padding:"10px 0", background:"#f5f5f5", color:BLUE, border:`2px solid ${BLUE}`, borderRadius:8, fontWeight:700, fontSize:13, cursor:"pointer" }}>📋 Copy HTML Email</button>
        )}
        {r.tel && <a href={`tel:${r.tel.replace(/\s/g,'')}`} style={{ display:"block", fontSize:13, color:BLUE, marginTop:8, textAlign:"center", fontWeight:700, textDecoration:"none", padding:"8px 0", background:"#f0f4ff", borderRadius:8 }}>📞 {r.tel}</a>}
        {onRenew && r._record && (
          <button onClick={()=>onRenew(r._record)}
            style={{ width:"100%", padding:"10px 0", marginTop:8, background:"#1a3a4a", color:"#fff200", border:"none", borderRadius:8, fontWeight:700, fontSize:13, cursor:"pointer", letterSpacing:0.3 }}>
            🔄 Renew Certificate
          </button>
        )}
      </div>
    );
  }

  const totalCount = autoReminders.length + pinnedReminders.length;

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="📬 Reminders Due" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        {totalCount === 0 ? (
          <div style={{ textAlign:"center", marginTop:60 }}>
            <div style={{ fontSize:48, marginBottom:12 }}>✅</div>
            <div style={{ fontWeight:700, fontSize:17, color:"#222", marginBottom:8 }}>No reminders</div>
            <div style={{ fontSize:13, color:"#888" }}>No records due within 30 days and none manually added.<br/>Tap any certificate record and choose <strong>Add to Reminders</strong>.</div>
          </div>
        ) : (
          <>
            {/* Due within 30 days */}
            {autoReminders.length > 0 && (
              <>
                <div style={{ fontWeight:700, fontSize:13, color:"#c00", marginBottom:10 }}>
                  ⚠️ Due within 30 days ({autoReminders.length})
                </div>
                {autoReminders.map((r, i) => <ReminderCard key={"auto"+i} r={r} i={i}/>)}
              </>
            )}

            {/* Manually pinned */}
            {pinnedReminders.length > 0 && (
              <>
                <div style={{ fontWeight:700, fontSize:13, color:"#888", marginBottom:10, marginTop: autoReminders.length>0?16:0 }}>
                  📬 Manually added reminders ({pinnedReminders.length})
                </div>
                {pinnedReminders.map((r, i) => <ReminderCard key={"pin"+i} r={r} i={i}/>)}
              </>
            )}
          </>
        )}
      </div>
      <BottomBar onHome={onHome}/>
    </div>
  );
}


// ─── COMMISSIONING CERTIFICATES FOLDER ───────────────────────────────────────

function CommissioningRecordsScreen({ records, onBack, onHome, onDelete, onCreateInvoice, onUpdateRecord, onRenew }) {
  const [subfolder, setSubfolder] = useState(null);

  if (subfolder === "benchmark") return <GenericCertRecordsScreen
    type="benchmark" records={records}
    onBack={()=>setSubfolder(null)} onHome={onHome}
    onDelete={onDelete} onCreateInvoice={onCreateInvoice}
    onUpdateRecord={onUpdateRecord} onRenew={onRenew}/>;

  const bmkCount = records.filter(r=>r.type==="benchmark").length;

  const subFolders = [
    { id:"benchmark", label:"Benchmark Commissioning Checklists", icon:"📋", count:bmkCount, color:"#6d9b3a",
      desc:"Gas boiler commissioning & handover" },
  ];

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Commissioning Certificates" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        <div style={{ background:"#fffbeb", border:"1.5px solid #f5c400", borderRadius:12, padding:"12px 14px", marginBottom:16, display:"flex", gap:10, alignItems:"flex-start" }}>
          <span style={{ fontSize:18, flexShrink:0 }}>📁</span>
          <div style={{ fontSize:13, color:"#444", lineHeight:1.6 }}>
            All commissioning certificates are stored here. Tap a folder to view, preview or download individual records.
          </div>
        </div>
        {subFolders.map(f => (
          <div key={f.id} onClick={()=>setSubfolder(f.id)}
            style={{ background:"#fff", borderRadius:12, padding:"16px 18px", marginBottom:12, boxShadow:"0 2px 10px rgba(0,0,0,0.07)", display:"flex", alignItems:"center", gap:16, cursor:"pointer" }}
            onMouseEnter={e=>e.currentTarget.style.background="#f0f4f0"}
            onMouseLeave={e=>e.currentTarget.style.background="#fff"}>
            <div style={{ width:52, height:52, borderRadius:12, background:`${f.color}18`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, fontSize:26 }}>
              {f.icon}
            </div>
            <div style={{ flex:1 }}>
              <div style={{ fontWeight:700, fontSize:15, color:"#222" }}>{f.label}</div>
              <div style={{ fontSize:13, color:"#888", marginTop:2 }}>{f.desc}</div>
              <div style={{ fontSize:12, color:"#aaa", marginTop:2 }}>{f.count} record{f.count!==1?"s":""}</div>
            </div>
            <svg width="18" height="18" viewBox="0 0 18 18" fill="none"><path d="M6 3L12 9L6 15" stroke="#bbb" strokeWidth="2.2" strokeLinecap="round"/></svg>
          </div>
        ))}
      </div>
      <BottomBar onHome={onHome}/>
    </div>
  );
}

// ─── Combined GSC + WN / GSC + BS Records Screen ─────────────────────────────
function CombinedRecordsScreen({ records, type, onBack, onHome, onDelete }) {
  const [combiningIdx, setCombiningIdx] = useState(null); // index of record being downloaded

  const myRecords = (records || [])
    .map((r, i) => ({ ...r, _origIdx: i }))
    .filter(r => r.type === type)
    .sort((a, b) => new Date(b.savedAt) - new Date(a.savedAt));

  const isWN = type === "gsc_wn_combined";
  const title = isWN ? "GSC + Warning Notice" : "GSC + Boiler Service";
  const accent = isWN ? "#b91c1c" : "#1a3a8f";

  // Active combine: build items for CombineRenderer
  const activeRec = combiningIdx !== null ? myRecords.find(r => r._origIdx === combiningIdx) : null;
  const combineItems = activeRec ? [
    { type: activeRec.gscRec?.type || "gsc", record: activeRec.gscRec },
    { type: isWN ? "wn" : "bs", record: activeRec.secondRec },
  ] : null;

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:"#f0f4f8", fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title={title} onBack={onBack} />
      <div style={{ flex:1, overflowY:"auto", padding:"12px 16px 100px" }}>
        {myRecords.length === 0 ? (
          <div style={{ textAlign:"center", color:"#aaa", marginTop:60, fontSize:15 }}>No combined records yet</div>
        ) : myRecords.map((rec) => {
          const dateStr = rec.savedAt ? new Date(rec.savedAt).toLocaleDateString("en-GB") : "";
          const isThis = combiningIdx === rec._origIdx;
          return (
            <div key={rec._origIdx} style={{ background:"#fff", borderRadius:12, padding:"14px 16px", marginBottom:10, boxShadow:"0 2px 10px rgba(0,0,0,0.07)" }}>
              <div style={{ fontWeight:700, fontSize:15, color:"#222", marginBottom:2 }}>{rec.label || (isWN ? "GSC + Warning Notice" : "GSC + Boiler Service")}</div>
              {dateStr && <div style={{ fontSize:12, color:"#999", marginBottom:10 }}>Saved {dateStr}</div>}
              <div style={{ display:"flex", gap:8 }}>
                <button
                  disabled={combiningIdx !== null}
                  onClick={() => { if (combiningIdx === null) setCombiningIdx(rec._origIdx); }}
                  style={{ flex:1, padding:"10px", background: isThis ? "#888" : combiningIdx !== null ? "#ccc" : accent, color:"#fff", border:"none", borderRadius:8, fontWeight:700, fontSize:13, cursor: combiningIdx !== null ? "default" : "pointer" }}>
                  {isThis ? "Building PDF…" : "⬇ Download Combined PDF"}
                </button>
                <button
                  disabled={combiningIdx !== null}
                  onClick={() => { if (combiningIdx === null && window.confirm("Delete this combined record?")) onDelete(rec._origIdx); }}
                  style={{ padding:"10px 14px", background:"#fee2e2", color:"#c00", border:"none", borderRadius:8, fontWeight:700, fontSize:13, cursor: combiningIdx !== null ? "default" : "pointer" }}>
                  🗑
                </button>
              </div>
            </div>
          );
        })}
      </div>
      <BottomBar onHome={onHome} />
      {/* CombineRenderer runs entirely off-screen — no overlay needed */}
      {combineItems && (
        <CombineRenderer
          items={combineItems}
          onAllDone={() => setCombiningIdx(null)}
        />
      )}
    </div>
  );
}


function RecordsScreen({ records, onBack, onHome, onDelete, onImport, onEditGw, onEditGi, invoices, onCreateInvoice, onDeleteInvoice, onMarkPaid, quotes, onDeleteQuote, onConvertQuoteToInvoice, onImportInvoices, onImportQuotes, onImportReports, onImportFolders, engineerData, accountReports, onDeleteReport, yearlyReports, onDeleteYearly, onRebuildYearly, onUpdateReport, gscFolders, onAddFolder, onRenameFolder, onDeleteFolder, onUpdateRecord, profile, onRenew, userPlan }) {
  const [folder, setFolder] = useState(null);

  if (folder === "reminders") {
    if (userPlan === "lite") return <FeatureLockedScreen feature="Annual Reminders" requiredPlan="Pro" onBack={()=>setFolder(null)} onHome={onHome}/>;
    return <RemindersScreen records={records} onBack={()=>setFolder(null)} onHome={onHome} engineerData={engineerData} onRenew={onRenew}/>;
  }
  if (folder === "gsc") return <GasSafetyCertsScreen records={records} onBack={()=>setFolder(null)} onHome={onHome} onDelete={onDelete} onCreateInvoice={onCreateInvoice} gscFolders={gscFolders} onAddFolder={onAddFolder} onRenameFolder={onRenameFolder} onDeleteFolder={onDeleteFolder} onUpdateRecord={onUpdateRecord}/>;
  if (folder === "bs") return <BoilerServiceRecordsScreen records={records} onBack={()=>setFolder(null)} onHome={onHome} onDelete={onDelete} onCreateInvoice={onCreateInvoice} onUpdateRecord={onUpdateRecord}/>;
  if (folder === "wn") return <WarningNoticeRecordsScreen records={records} onBack={()=>setFolder(null)} onHome={onHome} onDelete={onDelete} onCreateInvoice={onCreateInvoice}/>;
  if (folder === "inv") return <InvoicesScreen invoices={invoices} onBack={()=>setFolder(null)} onHome={onHome} onDelete={onDeleteInvoice} onMarkPaid={onMarkPaid} onImport={onCreateInvoice} profile={profile}/>;
  if (folder === "quotes") return <QuotesScreen quotes={quotes||[]} onBack={()=>setFolder(null)} onHome={onHome} onDelete={onDeleteQuote} onConvertToInvoice={(i)=>onConvertQuoteToInvoice(i)}/>;
  if (folder === "reports") return <AccountReportsScreen reports={accountReports||[]} onBack={()=>setFolder(null)} onHome={onHome} onDelete={(i)=>{ if(onDeleteReport) onDeleteReport(i); }} yearlyReports={yearlyReports||[]} onDeleteYearly={(i)=>{ if(onDeleteYearly) onDeleteYearly(i); }} onRebuildYearly={onRebuildYearly} onUpdateReport={onUpdateReport}/>;
  // Generic cert folders
  const GENERIC_CERT_TYPES = ["leisure_gsc","lpg_gsc","cooling_off","commercial_gsc","gas_install_report","catering_inspection","gas_test_purge","benchmark"];
  if (folder === "commissioning") return <CommissioningRecordsScreen records={records} onBack={()=>setFolder(null)} onHome={onHome} onDelete={onDelete} onCreateInvoice={onCreateInvoice} onUpdateRecord={onUpdateRecord} onRenew={onRenew}/>;
  const GENERIC_CERT_TYPES_EXCL = GENERIC_CERT_TYPES.filter(t=>t!=="benchmark");
  if (GENERIC_CERT_TYPES_EXCL.includes(folder)) return <GenericCertRecordsScreen type={folder} records={records} onBack={()=>setFolder(null)} onHome={onHome} onDelete={onDelete} onCreateInvoice={onCreateInvoice} onUpdateRecord={onUpdateRecord} onRenew={onRenew}/>;
  if (folder === "gsc_wn_combined") return <CombinedRecordsScreen type="gsc_wn_combined" records={records} onBack={()=>setFolder(null)} onHome={onHome} onDelete={onDelete}/>;
  if (folder === "gsc_bs_combined") return <CombinedRecordsScreen type="gsc_bs_combined" records={records} onBack={()=>setFolder(null)} onHome={onHome} onDelete={onDelete}/>;

  const exportRecords = () => {
    let exportedContacts = [];
    try { exportedContacts = JSON.parse(localStorage.getItem(sk("client_contacts")) || "[]"); } catch {}
    const bundle = {
      version: 3,
      exportedAt: new Date().toISOString(),
      records: records || [],
      invoices: invoices || [],
      quotes: quotes || [],
      accountReports: accountReports || [],
      yearlyReports: yearlyReports || [],
      gscFolders: gscFolders || [],
      contacts: exportedContacts,
    };
    const json = JSON.stringify(bundle, null, 2);
    const blob = new Blob([json], { type:"application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `wlg-all-records-${new Date().toISOString().slice(0,10)}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importRecords = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const data = JSON.parse(ev.target.result);
        if (Array.isArray(data)) {
          // Legacy: just certificates
          onImport(data);
          alert(`Imported ${data.length} certificate record(s).`);
        } else if (data.version === 2 || data.version === 3) {
          let certCount = 0, invCount = 0, quoteCount = 0, reportCount = 0, folderCount = 0;
          if (Array.isArray(data.records) && data.records.length) {
            onImport(data.records);
            certCount = data.records.length;
          }
          if (Array.isArray(data.invoices) && data.invoices.length && onImportInvoices) {
            onImportInvoices(data.invoices);
            invCount = data.invoices.length;
          }
          if (Array.isArray(data.quotes) && data.quotes.length && onImportQuotes) {
            onImportQuotes(data.quotes);
            quoteCount = data.quotes.length;
          }
          if (data.version === 3) {
            if (Array.isArray(data.accountReports) && data.accountReports.length && onImportReports) {
              onImportReports(data.accountReports, data.yearlyReports || []);
              reportCount = data.accountReports.length;
            }
            if (Array.isArray(data.gscFolders) && data.gscFolders.length && onImportFolders) {
              onImportFolders(data.gscFolders);
              folderCount = data.gscFolders.length;
            }
            if (Array.isArray(data.contacts) && data.contacts.length) {
              try {
                const existing = JSON.parse(localStorage.getItem(sk("client_contacts")) || "[]");
                const newOnes = data.contacts.filter(c => !existing.some(e =>
                  (c.phone && e.phone && c.phone === e.phone) ||
                  (c.email && e.email && c.email === e.email)
                ));
                localStorage.setItem(sk("client_contacts"), JSON.stringify([...existing, ...newOnes]));
              } catch {}
            }
          }
          alert(`✅ Import complete!\n${certCount} certificate(s)\n${invCount} invoice(s)\n${quoteCount} quote(s)${reportCount ? `\n${reportCount} account report(s)` : ""}${folderCount ? `\n${folderCount} GSC folder(s)` : ""}`);
        } else {
          alert("Invalid file format.");
        }
      } catch { alert("Could not read file."); }
    };
    reader.readAsText(file);
    e.target.value = "";
  };

  const gscCount = records.filter(r => !r.type || r.type==="gsc").length;
  const bsCount = records.filter(r => r.type==="bs").length;
  const wnCount = records.filter(r => r.type==="wn").length;
  const invCount = (invoices||[]).length;
  const quoteCount = (quotes||[]).length;

  // Badge count — only records due within 30 days (not just pinned)
  const now30 = new Date(); const cutoff30 = new Date(now30); cutoff30.setDate(cutoff30.getDate()+30);
  const autoDueCount = records.filter(r => {
    let dueDate = null;
    if (!r.type || r.type==="gsc") dueDate = r.finalChecks?.inspectionDate ? new Date(r.finalChecks.inspectionDate) : null;
    else if (r.type==="bs") { const rawD = r.bsEngData?.certDate || r.serviceData?.certDate || r.savedAt || null; const cd = rawD ? new Date(rawD) : null; dueDate = cd && !isNaN(cd) ? new Date(cd.getFullYear()+1,cd.getMonth(),cd.getDate()) : null; }
    return dueDate && !isNaN(dueDate) && dueDate >= now30 && dueDate <= cutoff30;
  }).length;
  const pinnedCount = records.filter(r => r.pinnedReminder).length;
  const dueCount = autoDueCount; // badge only for genuinely due records

  const reportCount = (accountReports||[]).length;
  const folders = [
    { id:"reminders", label:"Reminders Due", icon:"🔔", count: dueCount, color:"#c00", desc: autoDueCount>0 ? `${autoDueCount} due in 30 days${pinnedCount>0?` · ${pinnedCount} pinned`:""}` : pinnedCount>0 ? `${pinnedCount} pinned` : "None due" },
    { id:"gsc", label:"Gas Safety Certificates", icon:"🛡️", count: gscCount, color: BLUE },
    { id:"bs", label:"Boiler Service Records", icon:"🔩", count: bsCount, color: "#1a3a8f" },
    { id:"wn", label:"Warning Notices", icon:"🚨", count: wnCount, color: "#b91c1c" },
    { id:"leisure_gsc", label:"Leisure Industry Gas Safety Records", icon:"🏗️", count: records.filter(r=>r.type==="leisure_gsc").length, color:"#1d7a4a" },
    { id:"lpg_gsc", label:"LPG Gas Safety Records", icon:"🔶", count: records.filter(r=>r.type==="lpg_gsc").length, color:"#2563eb" },
    { id:"cooling_off", label:"7 Day Cooling Off Exemptions", icon:"📅", count: records.filter(r=>r.type==="cooling_off").length, color:"#0891b2" },
    { id:"commercial_gsc", label:"Commercial Gas Safety Certificates", icon:"🏛️", count: records.filter(r=>r.type==="commercial_gsc").length, color:"#7c3aed" },
    { id:"gas_install_report", label:"Gas Installation Safety Reports", icon:"📐", count: records.filter(r=>r.type==="gas_install_report").length, color:"#059669" },
    { id:"catering_inspection", label:"Commercial Catering Inspection Records", icon:"🍴", count: records.filter(r=>r.type==="catering_inspection").length, color:"#d97706" },
    { id:"gas_test_purge", label:"Gas Testing and Purging Records", icon:"⚗️", count: records.filter(r=>r.type==="gas_test_purge").length, color:"#be185d" },
    { id:"commissioning", label:"Commissioning Certificates", icon:"📋", count: records.filter(r=>r.type==="benchmark").length, color:"#6d9b3a", desc:"Benchmark & boiler commissioning checklists" },
    { id:"inv", label:"Invoices", icon:"💼", count: invCount, color: INV_GREEN_DARK },
    { id:"quotes", label:"Quotes", icon:"📄", count: quoteCount, color: BLUE },
    { id:"reports", label:"Account Reports", icon:"📈", count: reportCount, color: "#7c3aed" },
    { id:"gsc_wn_combined", label:"GSC + Warning Notice (Combined)", icon:"📑", count: records.filter(r=>r.type==="gsc_wn_combined").length, color:"#b91c1c", desc:"Combined Gas Safety & Warning Notice PDFs" },
    { id:"gsc_bs_combined", label:"GSC + Boiler Service (Combined)", icon:"📑", count: records.filter(r=>r.type==="gsc_bs_combined").length, color:"#1a3a8f", desc:"Combined Gas Safety & Boiler Service PDFs" },
  ];

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Records" onBack={onBack}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        {folders.map(f => (
          <div key={f.id} onClick={()=>setFolder(f.id)}
            style={{ background:"#fff", borderRadius:12, padding:"16px 18px", marginBottom:12, boxShadow:"0 2px 10px rgba(0,0,0,0.07)", display:"flex", alignItems:"center", gap:16, cursor:"pointer" }}
            onMouseEnter={e=>e.currentTarget.style.background="#f0f4f0"}
            onMouseLeave={e=>e.currentTarget.style.background="#fff"}>
            <div style={{ width:52, height:52, borderRadius:12, background:`${f.color}18`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, position:"relative", fontSize:26 }}>
              {f.icon}
              {f.id==="reminders" && dueCount>0 && (
                <div style={{ position:"absolute", top:-6, right:-6, background:"#c00", color:"#fff", borderRadius:"50%", minWidth:20, height:20, display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, fontWeight:700, padding:"0 3px" }}>
                  {dueCount}
                </div>
              )}
            </div>
            <div style={{ flex:1 }}>
              <div style={{ fontWeight:700, fontSize:15, color:"#222" }}>{f.label}</div>
              <div style={{ fontSize:13, color: f.id==="reminders" && f.count>0 ? "#c00" : "#888", marginTop:2 }}>
                {f.desc || `${f.count} record${f.count!==1?"s":""}`}
              </div>
            </div>
            <svg width="18" height="18" viewBox="0 0 18 18" fill="none"><path d="M6 3L12 9L6 15" stroke="#bbb" strokeWidth="2.2" strokeLinecap="round"/></svg>
          </div>
        ))}

        {/* Transfer records between devices */}
        <div style={{ marginTop:8, background:"#fff", borderRadius:12, padding:"16px 18px", boxShadow:"0 2px 10px rgba(0,0,0,0.07)" }}>
          <div style={{ fontWeight:700, fontSize:14, color:"#444", marginBottom:12 }}>📲 Transfer Records</div>
          <div style={{ fontSize:12, color:"#888", marginBottom:14, lineHeight:1.5 }}>Export <strong>everything</strong> — certificates, invoices, quotes, account reports, yearly reports, GSC folders and reminders — to a file, then import on another device to keep fully in sync.</div>
          <div style={{ display:"flex", gap:10 }}>
            <button onClick={exportRecords} style={{ flex:1, padding:"10px", background:BLUE, color:"#fff", border:"none", borderRadius:8, fontWeight:700, fontSize:13, cursor:"pointer" }}>
              ⬇ Export
            </button>
            <label style={{ flex:1, padding:"10px", background:"#f5f5f5", color:BLUE, border:`2px solid ${BLUE}`, borderRadius:8, fontWeight:700, fontSize:13, cursor:"pointer", textAlign:"center" }}>
              ⬆ Import
              <input type="file" accept=".json" onChange={importRecords} style={{ display:"none" }}/>
            </label>
          </div>
        </div>
      </div>
      <BottomBar onHome={onHome}/>
    </div>
  );
}

// ─── Email Template Parser (no API needed) ───────────────────────────────────
function parseEmailTemplate(text) {
  // Step 1: pre-process - split glued-together lines by inserting newlines before keywords
  // Handles cases where copy/paste collapses whitespace e.g. "===PROPERTY 1 ---"
  const keywords = ["PROPERTY", "APPLIANCE 1", "APPLIANCE 2", "APPLIANCE 3", "APPLIANCE 4", "APPLIANCE 5", "FAULT 1", "FAULT 2", "FAULT 3", "FAULT 4", "FAULT 5", "Client Name", "Client Address",
    "Client Postcode", "Client Tel", "Client Email", "Installation Address",
    "Installation Postcode", "Installation Tel", "Installation Name", "Installation Pass",
    "Gas Tightness", "Pipework Visual", "Emergency Control", "Bonding", "CO Alarm",
    "Smoke Alarm", "Cert Ref", "Location", "CO2 Reading",
    "CO Reading", "Flue Type", "Landlords Appliance", "Operating Pressure", "Heat Input",
    "Safety Devices", "Ventilation", "Flue Visual", "Flue Performance", "Appliance Serviced",
    "Appliance Safe", "Appliance Inspected", "Details", "Remedial Action", "Warning Notice"];

  // Insert a newline before any keyword that appears mid-line
  let processed = text;
  for (const kw of keywords) {
    // Insert newline before keyword if preceded by non-newline chars
    const re = new RegExp("([^\n])(" + kw.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + ")", "g");
    processed = processed.replace(re, "$1\n$2");
  }

  const lines = processed.split(/\r?\n/);
  const certs = [];
  let current = null;
  let currentAppliance = null;
  let currentFault = null;

  function field(line, label) {
    const prefix = label + ":";
    if (line.trim().toUpperCase().startsWith(prefix.toUpperCase())) {
      return line.trim().slice(prefix.length).trim();
    }
    return null;
  }

  function saveAppliance() {
    if (currentAppliance && current) { current.appliances.push(currentAppliance); currentAppliance = null; }
  }
  function saveFault() {
    if (currentFault && current) { current.faults.push(currentFault); currentFault = null; }
  }
  function saveCert() {
    saveAppliance(); saveFault();
    if (current) certs.push(current);
    current = null;
  }

  for (let i = 0; i < lines.length; i++) {
    const trimmed = lines[i].trim();

    // Strip leading = - characters to catch "===PROPERTY 1 ---" style lines
    const stripped = trimmed.replace(/^[=\-\s]+/, "").trim();

    if (stripped.length > 0 && /^PROPERTY\s*\d/i.test(stripped)) {
      saveCert();
      current = { certRef:"", clientName:"", clientAddr1:"", clientAddr2:"", clientAddr3:"", clientPostcode:"", clientTel:"", clientEmail:"", instName:"", instAddr1:"", instAddr2:"", instAddr3:"", instPostcode:"", instTel:"", gasTightness:"YES", pipeworkVisual:"YES", emergencyControl:"YES", bonding:"YES", installationPass:"YES", coAlarm:"YES", smokeAlarm:"YES", appliances:[], faults:[] };
      continue;
    }
    if (/^APPLIANCE\s+\d/i.test(stripped)) {
      saveAppliance(); saveFault();
      currentAppliance = { location:"", type:"", make:"", model:"", co2:"", co:"", flueType:"", applianceInspected:"Yes", combustion:"", landlordsAppliance:"Yes", operatingPressure:"", heatInput:"", safetyDevices:"Yes", ventilation:"Yes", flueVisual:"Yes", fluePerformance:"PASS", applianceServiced:"Yes", applianceSafe:"Yes" };
      continue;
    }
    if (/^FAULT\s+\d/i.test(stripped)) {
      saveAppliance(); saveFault();
      currentFault = { details:"", remedial:"", warningNotice:"No" };
      continue;
    }
    if (/^END OF JOB/i.test(stripped)) { saveCert(); continue; }

    if (!current) continue;

    const v = (lbl) => field(trimmed, lbl);
    if (v("Cert Ref") !== null) { current.certRef = v("Cert Ref"); continue; }
    if (v("Cert Reference") !== null) { current.certRef = v("Cert Reference"); continue; }
    if (v("Client Name") !== null) { current.clientName = v("Client Name"); continue; }
    if (v("Client Address 1") !== null) { current.clientAddr1 = v("Client Address 1"); continue; }
    if (v("Client Address 2") !== null) { current.clientAddr2 = v("Client Address 2"); continue; }
    if (v("Client Address 3") !== null) { current.clientAddr3 = v("Client Address 3"); continue; }
    if (v("Client Postcode") !== null) { current.clientPostcode = v("Client Postcode"); continue; }
    if (v("Client Tel") !== null) { current.clientTel = v("Client Tel"); continue; }
    if (v("Client Email") !== null) { current.clientEmail = v("Client Email"); continue; }
    if (v("Installation Address 1") !== null) { current.instAddr1 = v("Installation Address 1"); continue; }
    if (v("Installation Address 2") !== null) { current.instAddr2 = v("Installation Address 2"); continue; }
    if (v("Installation Address 3") !== null) { current.instAddr3 = v("Installation Address 3"); continue; }
    if (v("Installation Postcode") !== null) { current.instPostcode = v("Installation Postcode"); continue; }
    if (v("Installation Tel") !== null) { current.instTel = v("Installation Tel"); continue; }
    if (v("Installation Name") !== null) { current.instName = v("Installation Name"); continue; }
    if (v("Gas Tightness") !== null) { current.gasTightness = v("Gas Tightness"); continue; }
    if (v("Pipework Visual") !== null) { current.pipeworkVisual = v("Pipework Visual"); continue; }
    if (v("Emergency Control") !== null) { current.emergencyControl = v("Emergency Control"); continue; }
    if (v("Bonding") !== null) { current.bonding = v("Bonding"); continue; }
    if (v("Installation Pass") !== null) { current.installationPass = v("Installation Pass"); continue; }
    if (v("CO Alarm") !== null) { current.coAlarm = v("CO Alarm"); continue; }
    if (v("Smoke Alarm") !== null) { current.smokeAlarm = v("Smoke Alarm"); continue; }

    if (currentAppliance) {
      if (v("Location") !== null) { currentAppliance.location = v("Location"); continue; }
      if (v("Type") !== null && !trimmed.toUpperCase().startsWith("FLUE TYPE")) { currentAppliance.type = v("Type"); continue; }
      if (v("Make") !== null) { currentAppliance.make = v("Make"); continue; }
      if (v("Model") !== null) { currentAppliance.model = v("Model"); continue; }
      if (v("CO2 Reading") !== null) { currentAppliance.co2 = v("CO2 Reading"); continue; }
      if (v("CO Reading") !== null) { currentAppliance.co = v("CO Reading"); continue; }
      if (v("Flue Type") !== null) { currentAppliance.flueType = v("Flue Type"); continue; }
      if (v("Appliance Inspected") !== null) {
        const aiVal = v("Appliance Inspected");
        // Handle "Appliance Inspected: Yes Combustion Analysis: 0.001" on same line
        const caIdx = aiVal.toUpperCase().indexOf("COMBUSTION ANALYSIS:");
        if (caIdx >= 0) {
          currentAppliance.applianceInspected = aiVal.slice(0, caIdx).trim();
          currentAppliance.combustion = aiVal.slice(caIdx + "Combustion Analysis:".length).trim();
        } else {
          currentAppliance.applianceInspected = aiVal;
        }
        continue;
      }
      if (v("Combustion Analysis") !== null) { currentAppliance.combustion = v("Combustion Analysis"); continue; }
      if (v("Landlords Appliance") !== null) { currentAppliance.landlordsAppliance = v("Landlords Appliance"); continue; }
      if (v("Operating Pressure") !== null) { currentAppliance.operatingPressure = v("Operating Pressure"); continue; }
      if (v("Heat Input") !== null) { currentAppliance.heatInput = v("Heat Input"); continue; }
      if (v("Safety Devices") !== null) { currentAppliance.safetyDevices = v("Safety Devices"); continue; }
      if (v("Ventilation") !== null) { currentAppliance.ventilation = v("Ventilation"); continue; }
      if (v("Flue Visual") !== null) { currentAppliance.flueVisual = v("Flue Visual"); continue; }
      if (v("Flue Performance") !== null) { currentAppliance.fluePerformance = v("Flue Performance"); continue; }
      if (v("Appliance Serviced") !== null) { currentAppliance.applianceServiced = v("Appliance Serviced"); continue; }
      if (v("Appliance Safe") !== null) { currentAppliance.applianceSafe = v("Appliance Safe"); continue; }
    }

    if (currentFault) {
      if (v("Details") !== null) { currentFault.details = v("Details"); continue; }
      if (v("Remedial Action") !== null) { currentFault.remedial = v("Remedial Action"); continue; }
      if (v("Warning Notice") !== null) { currentFault.warningNotice = v("Warning Notice"); continue; }
    }
  }

  saveCert();
  return certs;
}

// ─── Gas Safety Certificate Email Screen ─────────────────────────────────────

function parseGSCEmailTemplate(text) {
  const keywords = ["APPLIANCE", "FAULT", "Cert Ref", "Date", "Client Name", "Client Address 1", "Client Address 2", "Client Address 3", "Client Postcode", "Client Tel", "Client Email", "Install Name", "Install Address 1", "Install Address 2", "Install Address 3", "Install Postcode", "Install Tel", "Gas Tightness", "Pipework Visual", "Emergency Control", "Bonding", "Installation Pass", "CO Alarm", "Smoke Alarm", "Location", "Flue Type", "Flue Visual", "Flue Performance", "Type", "Make", "Model", "CO2", "CO", "Combustion Analyser", "Operating Pressure", "Heat Input", "Landlords Appliance", "Appliance Inspected", "Safety Devices", "Ventilation", "Fault Details", "Remedial Work Taken", "Warning Notice Fixed", "Appliance Safe", "Appliance Serviced", "END OF JOB"];
  let processed = text;
  processed = processed.replace(/([^\n])(PROPERTY\s*\d)/gi, "$1\n$2");
  for (const kw of keywords) {
    if (kw === "Type") {
      // Prevent splitting on "Type" when it's part of "Flue Type"
      processed = processed.replace(/([^\n])(?<![Ff]lue )(Type)/g, "$1\n$3");
    } else {
      const re = new RegExp("([^\n])(" + kw.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + ")", "g");
      processed = processed.replace(re, "$1\n$2");
    }
  }
  const lines = processed.split(/\r?\n/);
  const records = [];
  let current = null;
  let currentAppliance = null;

  function field(line, label) {
    const prefix = label + ":";
    if (line.trim().toUpperCase().startsWith(prefix.toUpperCase()))
      return line.trim().slice(prefix.length).trim();
    return null;
  }

  function saveAppliance() {
    if (currentAppliance && current) { current.appliances.push(currentAppliance); currentAppliance = null; }
  }

  function saveFault() {
    if (currentFault && current) { current.faults.push(currentFault); currentFault = null; }
  }

  function saveCurrent() {
    saveAppliance();
    saveFault();
    if (current) records.push(current);
    current = null;
  }

  let currentFault = null;

  for (const rawLine of lines) {
    const trimmed = rawLine.trim();
    const stripped = trimmed.replace(/^[=\-\s]+/, "").trim();

    if (stripped.length > 0 && /^PROPERTY\s*\d/i.test(stripped)) {
      saveCurrent();
      current = { certRef:"", date:"", clientName:"", clientAddr1:"", clientAddr2:"", clientAddr3:"", clientPostcode:"", clientTel:"", clientEmail:"", instName:"", instAddr1:"", instAddr2:"", instAddr3:"", instPostcode:"", instTel:"", gasTightness:"YES", pipeworkVisual:"YES", emergencyControl:"YES", bonding:"YES", installationPass:"YES", coAlarm:"YES", smokeAlarm:"YES", appliances:[], faults:[] };
      continue;
    }
    if (/^APPLIANCE\s*\d/i.test(stripped)) {
      saveAppliance();
      saveFault();
      currentAppliance = { location:"", type:"", make:"", model:"", flueType:"", landlordsAppliance:"N/A", applianceInspected:"N/A", co2:"", co:"", combustion:"", operatingPressure:"", heatInput:"", spillageTest:"N/A", flueFlow:"N/A", ventilation:"N/A", flueVisual:"N/A", fluePerformance:"N/A", applianceServiced:"N/A", applianceSafe:"N/A", safetyDevices:"N/A" };
      continue;
    }
    if (/^FAULT\s*\d/i.test(stripped)) {
      saveAppliance();
      saveFault();
      currentFault = { details:"", remedial:"", warningNotice:"" };
      continue;
    }
    if (/^END OF JOB/i.test(stripped)) { saveCurrent(); continue; }
    if (!current) continue;

    const v = (lbl) => field(trimmed, lbl);

    if (currentAppliance) {
      if (v("Location") !== null)             { currentAppliance.location = v("Location"); continue; }
      if (v("Flue Type") !== null)            { currentAppliance.flueType = v("Flue Type"); continue; }
      if (v("Type") !== null)                 { currentAppliance.type = v("Type"); continue; }
      if (v("Make") !== null)                 { currentAppliance.make = v("Make"); continue; }
      if (v("Model") !== null)                { currentAppliance.model = v("Model"); continue; }
      if (v("CO2") !== null)                  { currentAppliance.co2 = v("CO2"); continue; }
      if (v("CO") !== null)                   { currentAppliance.co = v("CO"); continue; }
      if (v("Combustion Analyser") !== null)  { currentAppliance.combustion = v("Combustion Analyser"); continue; }
      if (v("Operating Pressure") !== null)   { currentAppliance.operatingPressure = v("Operating Pressure"); continue; }
      if (v("Heat Input") !== null)           { currentAppliance.heatInput = v("Heat Input"); continue; }
      if (v("Landlords Appliance") !== null)  { currentAppliance.landlordsAppliance = v("Landlords Appliance"); continue; }
      if (v("Appliance Inspected") !== null)  { currentAppliance.applianceInspected = v("Appliance Inspected"); continue; }
      if (v("Safety Devices") !== null)       { currentAppliance.safetyDevices = v("Safety Devices"); continue; }
      if (v("Ventilation") !== null)          { currentAppliance.ventilation = v("Ventilation"); continue; }
      if (v("Flue Visual") !== null)          { currentAppliance.flueVisual = v("Flue Visual"); continue; }
      if (v("Flue Performance") !== null)     { currentAppliance.fluePerformance = v("Flue Performance"); continue; }
      if (v("Appliance Safe") !== null)       { currentAppliance.applianceSafe = v("Appliance Safe"); continue; }
      if (v("Appliance Serviced") !== null)   { currentAppliance.applianceServiced = v("Appliance Serviced"); continue; }
    }

    if (currentFault) {
      if (v("Fault Details") !== null)         { currentFault.details = v("Fault Details"); continue; }
      if (v("Remedial Work Taken") !== null)   { currentFault.remedial = v("Remedial Work Taken"); continue; }
      if (v("Warning Notice Fixed") !== null)  { currentFault.warningNotice = v("Warning Notice Fixed"); continue; }
    }

    if (v("Cert Ref") !== null)           { current.certRef = v("Cert Ref"); continue; }
    if (v("Date") !== null)               { current.date = v("Date"); continue; }
    if (v("Client Name") !== null)        { current.clientName = v("Client Name"); continue; }
    if (v("Client Address 1") !== null)   { current.clientAddr1 = v("Client Address 1"); continue; }
    if (v("Client Address 2") !== null)   { current.clientAddr2 = v("Client Address 2"); continue; }
    if (v("Client Address 3") !== null)   { current.clientAddr3 = v("Client Address 3"); continue; }
    if (v("Client Postcode") !== null)    { current.clientPostcode = v("Client Postcode"); continue; }
    if (v("Client Tel") !== null)         { current.clientTel = v("Client Tel"); continue; }
    if (v("Client Email") !== null)       { current.clientEmail = v("Client Email"); continue; }
    if (v("Install Name") !== null)       { current.instName = v("Install Name"); continue; }
    if (v("Install Address 1") !== null)  { current.instAddr1 = v("Install Address 1"); continue; }
    if (v("Install Address 2") !== null)  { current.instAddr2 = v("Install Address 2"); continue; }
    if (v("Install Address 3") !== null)  { current.instAddr3 = v("Install Address 3"); continue; }
    if (v("Install Postcode") !== null)   { current.instPostcode = v("Install Postcode"); continue; }
    if (v("Install Tel") !== null)        { current.instTel = v("Install Tel"); continue; }
    if (v("Gas Tightness") !== null)      { current.gasTightness = v("Gas Tightness"); continue; }
    if (v("Pipework Visual") !== null)    { current.pipeworkVisual = v("Pipework Visual"); continue; }
    if (v("Emergency Control") !== null)  { current.emergencyControl = v("Emergency Control"); continue; }
    if (v("Bonding") !== null)            { current.bonding = v("Bonding"); continue; }
    if (v("Installation Pass") !== null)  { current.installationPass = v("Installation Pass"); continue; }
    if (v("CO Alarm") !== null)           { current.coAlarm = v("CO Alarm"); continue; }
    if (v("Smoke Alarm") !== null)        { current.smokeAlarm = v("Smoke Alarm"); continue; }
  }
  saveCurrent();
  return records;
}

function GasSafetyCertEmailScreen({ onBack, onHome, onImport, defaultEngineerData }) {
  const [tab, setTab] = useState("send");
  const [propertyCount, setPropertyCount] = useState(1);
  const [applianceCount, setApplianceCount] = useState(1);
  const [copied, setCopied] = useState(false);
  const [emailText, setEmailText] = useState("");
  const [parsed, setParsed] = useState([]);
  const [parseStatus, setParseStatus] = useState("idle");
  const [parseMsg, setParseMsg] = useState("");

  const GSC_EMAIL = "lspapandh@gmail.com";

  function buildTemplate() {
    let tmpl = "GAS SAFETY CERTIFICATE REQUEST\n";
    tmpl += "=".repeat(40) + "\n\n";
    tmpl += "Please fill in the details below for each property and send back.\n\n";
    for (let i = 1; i <= propertyCount; i++) {
      tmpl += `PROPERTY ${i}\n`;
      tmpl += "-".repeat(30) + "\n";
      tmpl += "Cert Ref: \n";
      tmpl += "Date: \n";
      tmpl += "Client Name: \n";
      tmpl += "Client Address 1: \n";
      tmpl += "Client Address 2: \n";
      tmpl += "Client Address 3: \n";
      tmpl += "Client Postcode: \n";
      tmpl += "Client Tel: \n";
      tmpl += "Client Email: \n";
      tmpl += "Install Name: \n";
      tmpl += "Install Address 1: \n";
      tmpl += "Install Address 2: \n";
      tmpl += "Install Postcode: \n";
      tmpl += "Install Tel: \n";
      tmpl += "Gas Tightness: YES\n";
      tmpl += "Pipework Visual: YES\n";
      tmpl += "Emergency Control: YES\n";
      tmpl += "Bonding: YES\n";
      tmpl += "Installation Pass: YES\n";
      tmpl += "CO Alarm: YES\n";
      tmpl += "Smoke Alarm: YES\n";
      tmpl += "\n";
      for (let j = 1; j <= applianceCount; j++) {
        tmpl += `APPLIANCE ${j}\n`;
        tmpl += "Location: \n";
        tmpl += "Type: (Heat Only / System / Combi / Cooker / Fire / Hob)\n";
        tmpl += "Make: \n";
        tmpl += "Model: \n";
        tmpl += "Flue Type: (FL / OF / RS / N/A)\n";
        tmpl += "CO2: \n";
        tmpl += "CO: \n";
        tmpl += "Combustion Analyser: \n";
        tmpl += "Operating Pressure: \n";
        tmpl += "Heat Input: \n";
        tmpl += "Landlords Appliance: (Yes / No / N/A)\n";
        tmpl += "Appliance Inspected: (Yes / No / N/A / VIO)\n";
        tmpl += "Safety Devices: (Yes / No / N/A)\n";
        tmpl += "Ventilation: (Yes / No / N/A)\n";
        tmpl += "Flue Visual: (Yes / No / N/A)\n";
        tmpl += "Flue Performance: (Pass / Fail / N/A)\n";
        tmpl += "Appliance Safe: (N/A / Yes / No)\n";
        tmpl += "Appliance Serviced: (N/A / Yes / No)\n";
        tmpl += "\n";
      }
      tmpl += "FAULTS (leave blank if none)\n";
      tmpl += "-".repeat(30) + "\n";
      for (let f = 1; f <= 5; f++) {
        tmpl += `FAULT ${f}\n`;
        tmpl += "Fault Details: \n";
        tmpl += "Remedial Work Taken: \n";
        tmpl += "Warning Notice Fixed: \n";
        tmpl += "\n";
      }
    }
    tmpl += "END OF JOB";
    return tmpl;
  }

  function copyTemplate() {
    navigator.clipboard.writeText(buildTemplate()).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  }

  function openMailto() {
    const body = encodeURIComponent(buildTemplate());
    const subject = encodeURIComponent("Gas Safety Certificate Request");
    window.open(`mailto:${GSC_EMAIL}?subject=${subject}&body=${body}`, "_blank");
  }

  function doParse() {
    if (!emailText.trim()) return;
    setParseStatus("loading");
    try {
      const results = parseGSCEmailTemplate(emailText);
      if (!results || results.length === 0) throw new Error("No PROPERTY blocks found. Make sure the email uses the correct template format.");
      setParsed(results);
      setParseStatus("parsed");
      setParseMsg(`Found ${results.length} propert${results.length===1?"y":"ies"} ready to import.`);
    } catch(e) {
      setParseStatus("error");
      setParseMsg("Error: " + e.message);
    }
  }

  function doImport() {
    const now = new Date();
    const newRecords = parsed.map((cert, i) => ({
      certData: {
        certRef: cert.certRef || ("GSC-" + (now.getTime() + i)),
        clientName: cert.clientName || "",
        clientAddr1: cert.clientAddr1 || "",
        clientAddr2: cert.clientAddr2 || "",
        clientAddr3: cert.clientAddr3 || "",
        clientPostcode: cert.clientPostcode || "",
        clientTel: cert.clientTel || "",
        clientEmail: cert.clientEmail || "",
        instName: cert.instName || cert.clientName || "",
        instAddr1: cert.instAddr1 || cert.clientAddr1 || "",
        instAddr2: cert.instAddr2 || cert.clientAddr2 || "",
        instAddr3: cert.instAddr3 || cert.clientAddr3 || "",
        instPostcode: cert.instPostcode || cert.clientPostcode || "",
        instTel: cert.instTel || cert.clientTel || "",
      },
      appliances: cert.appliances || [],
      faults: (cert.faults || []).filter(f => f.details || f.remedial || f.warningNotice),
      finalChecks: {
        gasTightness: cert.gasTightness || "YES",
        pipeworkVisual: cert.pipeworkVisual || "YES",
        emergencyControl: cert.emergencyControl || "YES",
        bonding: cert.bonding || "YES",
        installationPass: cert.installationPass || "YES",
        coAlarm: cert.coAlarm || "YES",
        smokeAlarm: cert.smokeAlarm || "YES",
        inspectionDate: (() => { 
          const base = cert.date ? new Date(normaliseDate(cert.date)) : new Date();
          const d = isNaN(base.getTime()) ? new Date() : new Date(base);
          d.setFullYear(d.getFullYear() + 1); 
          return d; 
        })(),
      },
      signatureData: (()=>{ try { const sig=localStorage.getItem(sk("gsc_engineer_sig")); return sig ? {engineerSigImage: sig} : {}; } catch(e){return {};} })(),
      engineerData: { ...defaultEngineerData, certDate: (() => { if (cert.date) { const iso = normaliseDate(cert.date); const d = new Date(iso); return isNaN(d.getTime()) ? now : d; } return now; })() },
      savedAt: new Date(now.getTime() + i * 1000).toISOString(),
    }));
    onImport(newRecords);
    alert(`✅ ${newRecords.length} Gas Safety Certificate${newRecords.length===1?"":"s"} created!`);
    onHome();
  }

  const tabStyle = (active) => ({
    flex:1, padding:"11px 0", border:"none", cursor:"pointer", fontWeight:700, fontSize:14,
    fontFamily:"'Segoe UI',sans-serif",
    background: active ? BLUE : "#f0f2f8",
    color: active ? "#fff" : "#666",
    borderRadius: 0,
    transition:"all 0.15s",
  });

  const counterRow = (label, value, onDec, onInc) => (
    <div style={{ marginBottom:14 }}>
      <label style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:6, display:"block" }}>{label}</label>
      <div style={{ display:"flex", alignItems:"center", gap:12 }}>
        <button onClick={onDec} style={{ width:38, height:38, borderRadius:"50%", border:"2px solid #ddd", background:"#f5f5f5", fontSize:20, cursor:"pointer", fontWeight:700 }}>−</button>
        <span style={{ fontSize:24, fontWeight:800, color:BLUE, minWidth:32, textAlign:"center" }}>{value}</span>
        <button onClick={onInc} style={{ width:38, height:38, borderRadius:"50%", border:"2px solid #ddd", background:"#f5f5f5", fontSize:20, cursor:"pointer", fontWeight:700 }}>+</button>
      </div>
    </div>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="GSC Email" onBack={onBack} onHome={onHome}/>

      <div style={{ display:"flex", flexShrink:0, borderBottom:"2px solid #dde" }}>
        <button style={tabStyle(tab==="send")} onClick={()=>setTab("send")}>📤 Send Template</button>
        <button style={tabStyle(tab==="import")} onClick={()=>setTab("import")}>📥 Import Reply</button>
      </div>

      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>

        {tab === "send" && (
          <div>
            <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:14, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
              <p style={{ fontSize:13, color:"#444", marginBottom:14, lineHeight:1.6 }}>
                Choose how many properties and appliances per property, then send the template to <strong>{GSC_EMAIL}</strong>. Once filled in and replied, come back to the <em>Import Reply</em> tab.
              </p>
              {counterRow("Number of Properties", propertyCount, ()=>setPropertyCount(c=>Math.max(1,c-1)), ()=>setPropertyCount(c=>Math.min(20,c+1)))}
              {counterRow("Appliances per Property", applianceCount, ()=>setApplianceCount(c=>Math.max(1,c-1)), ()=>setApplianceCount(c=>Math.min(10,c+1)))}
              <button onClick={openMailto} style={{ width:"100%", background:BLUE, color:"#fff", border:"none", borderRadius:12, padding:"13px", fontSize:15, fontWeight:700, cursor:"pointer", marginBottom:10 }}>
                ✉️ Open in Mail App
              </button>
              <button onClick={copyTemplate} style={{ width:"100%", background:"#fff", color:BLUE, border:`2px solid ${BLUE}`, borderRadius:12, padding:"13px", fontSize:15, fontWeight:700, cursor:"pointer" }}>
                {copied ? "✅ Copied!" : "📋 Copy Template"}
              </button>
            </div>

            <div style={{ background:"#fff", borderRadius:12, padding:14, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
              <p style={{ fontSize:12, fontWeight:700, color:"#888", marginBottom:8, textTransform:"uppercase", letterSpacing:"0.05em" }}>Template Preview</p>
              <pre style={{ fontSize:12, color:"#333", whiteSpace:"pre-wrap", margin:0, fontFamily:"monospace", lineHeight:1.7 }}>{buildTemplate()}</pre>
            </div>
          </div>
        )}

        {tab === "import" && (
          <div>
            <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:14, boxShadow:"0 1px 4px rgba(0,0,0,0.06)", fontSize:13, color:"#444", lineHeight:1.6 }}>
              Paste the completed reply email below and tap <strong>Parse</strong>. A Gas Safety Certificate record and PDF will be created for each property automatically.
            </div>

            <textarea
              value={emailText}
              onChange={e=>{ setEmailText(e.target.value); setParseStatus("idle"); setParseMsg(""); }}
              placeholder={"Paste the completed email reply here...\n\nPROPERTY 1\n-----\nCert Ref: GSC-001\nClient Name: John Smith\nClient Address 1: 47 High Street\n..."}
              style={{ width:"100%", minHeight:160, borderRadius:10, border:"1px solid #ddd", padding:"10px 12px", fontSize:13, fontFamily:"monospace", resize:"vertical", boxSizing:"border-box", marginBottom:10 }}
            />
            <button onClick={doParse} disabled={!emailText.trim()} style={{ width:"100%", background:"#fff", color:BLUE, border:`2px solid ${BLUE}`, borderRadius:12, padding:"12px", fontSize:14, fontWeight:700, cursor:"pointer", marginBottom:14, opacity:!emailText.trim()?0.5:1 }}>
              Parse Email
            </button>

            {parseMsg && (
              <div style={{ background: parseStatus==="error"?"#fff3f3":parseStatus==="parsed"?"#f0fff4":"#f5f5f5", border:`1px solid ${parseStatus==="error"?"#ffcdd2":parseStatus==="parsed"?"#c8e6c9":"#c5cae9"}`, borderRadius:10, padding:"12px 14px", marginBottom:14, fontSize:13, color: parseStatus==="error"?"#c62828":parseStatus==="parsed"?"#2e7d32":"#1a3a8f" }}>
                {parseMsg}
              </div>
            )}

            {parseStatus==="parsed" && parsed.length > 0 && (
              <div>
                {parsed.map((cert, i) => (
                  <div key={i} style={{ border:"1px solid #e0e0e0", borderRadius:10, padding:"12px 14px", marginBottom:10, fontSize:13, background:"#fff" }}>
                    <div style={{ fontWeight:700, color:BLUE, marginBottom:4 }}>Property {i+1}: {cert.clientAddr1 || cert.clientName || "—"}</div>
                    <div style={{ color:"#555" }}>Client: {cert.clientName || "—"}</div>
                    <div style={{ color:"#555" }}>Cert Ref: {cert.certRef || "—"}</div>
                    <div style={{ color:"#555" }}>Appliances: {cert.appliances.length}</div>
                    {cert.instAddr1 && <div style={{ color:"#555" }}>Install: {cert.instAddr1}</div>}
                  </div>
                ))}
                <button onClick={doImport} style={{ width:"100%", background:"#2e7d32", color:"#fff", border:"none", borderRadius:12, padding:"15px", fontSize:16, fontWeight:700, cursor:"pointer", marginTop:6 }}>
                  ✅ Create {parsed.length} Gas Safety Certificate{parsed.length!==1?"s":""}
                </button>
              </div>
            )}
          </div>
        )}

      </div>
    </div>
  );
}

// ─── Boiler Service Email Screen ─────────────────────────────────────────────

function parseBSEmailTemplate(text) {
  const keywords = ["Cert Ref", "Client Name", "Client Address 1", "Client Address 2", "Client Address 3", "Client Postcode", "Client Tel", "Client Email", "Install Name", "Install Address 1", "Install Address 2", "Install Address 3", "Install Postcode", "Install Tel", "Work Type Service", "Work Type Breakdown", "Boiler Make", "Boiler Model", "Boiler Serial", "Appliance Make", "Appliance Model", "Appliance Serial", "CO Reading", "CO2 Reading", "CO/CO2 Ratio", "Additional Notes", "Spares Required", "END OF JOB"];
  let processed = text;
  processed = processed.replace(/([^\n])(PROPERTY\s*\d)/gi, "$1\n$2");
  for (const kw of keywords) {
    const re = new RegExp("([^\n])(" + kw.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + ")", "g");
    processed = processed.replace(re, "$1\n$2");
  }
  const lines = processed.split(/\r?\n/);
  const records = [];
  let current = null;

  function field(line, label) {
    const prefix = label + ":";
    if (line.trim().toUpperCase().startsWith(prefix.toUpperCase()))
      return line.trim().slice(prefix.length).trim();
    return null;
  }

  function saveCurrent() {
    if (current) records.push(current);
    current = null;
  }

  for (const rawLine of lines) {
    const trimmed = rawLine.trim();
    const stripped = trimmed.replace(/^[=\-\s]+/, "").trim();

    if (stripped.length > 0 && /^PROPERTY\s*\d/i.test(stripped)) {
      saveCurrent();
      current = {
        certRef:"", clientName:"", clientAddr1:"", clientAddr2:"", clientAddr3:"",
        clientPostcode:"", clientTel:"", clientEmail:"",
        instName:"", instAddr1:"", instAddr2:"", instAddr3:"", instPostcode:"", instTel:"",
        typeOfWorkService:"N/A", typeOfWorkBreakdown:"N/A",
        boilerMake:"", boilerModel:"", boilerSerial:"",
        applianceMake:"", applianceModel:"", applianceSerial:"",
        coReading:"", co2Reading:"", coCo2Ratio:"",
        additionalNotes:"", sparesRequired:"",
      };
      continue;
    }
    if (/^END OF JOB/i.test(stripped)) { saveCurrent(); continue; }
    if (!current) continue;

    const v = (lbl) => field(trimmed, lbl);
    if (v("Cert Ref") !== null)            { current.certRef = v("Cert Ref"); continue; }
    if (v("Client Name") !== null)         { current.clientName = v("Client Name"); continue; }
    if (v("Client Address 1") !== null)    { current.clientAddr1 = v("Client Address 1"); continue; }
    if (v("Client Address 2") !== null)    { current.clientAddr2 = v("Client Address 2"); continue; }
    if (v("Client Address 3") !== null)    { current.clientAddr3 = v("Client Address 3"); continue; }
    if (v("Client Postcode") !== null)     { current.clientPostcode = v("Client Postcode"); continue; }
    if (v("Client Tel") !== null)          { current.clientTel = v("Client Tel"); continue; }
    if (v("Client Email") !== null)        { current.clientEmail = v("Client Email"); continue; }
    if (v("Install Name") !== null)        { current.instName = v("Install Name"); continue; }
    if (v("Install Address 1") !== null)   { current.instAddr1 = v("Install Address 1"); continue; }
    if (v("Install Address 2") !== null)   { current.instAddr2 = v("Install Address 2"); continue; }
    if (v("Install Address 3") !== null)   { current.instAddr3 = v("Install Address 3"); continue; }
    if (v("Install Postcode") !== null)    { current.instPostcode = v("Install Postcode"); continue; }
    if (v("Install Tel") !== null)         { current.instTel = v("Install Tel"); continue; }
    if (v("Work Type Service") !== null)   { current.typeOfWorkService = v("Work Type Service"); continue; }
    if (v("Work Type Breakdown") !== null) { current.typeOfWorkBreakdown = v("Work Type Breakdown"); continue; }
    if (v("Boiler Make") !== null)         { current.boilerMake = v("Boiler Make"); continue; }
    if (v("Boiler Model") !== null)        { current.boilerModel = v("Boiler Model"); continue; }
    if (v("Boiler Serial") !== null)       { current.boilerSerial = v("Boiler Serial"); continue; }
    if (v("Appliance Make") !== null)      { current.applianceMake = v("Appliance Make"); continue; }
    if (v("Appliance Model") !== null)     { current.applianceModel = v("Appliance Model"); continue; }
    if (v("Appliance Serial") !== null)    { current.applianceSerial = v("Appliance Serial"); continue; }
    if (v("CO Reading") !== null)          { current.coReading = v("CO Reading"); continue; }
    if (v("CO2 Reading") !== null)         { current.co2Reading = v("CO2 Reading"); continue; }
    if (v("CO/CO2 Ratio") !== null)        { current.coCo2Ratio = v("CO/CO2 Ratio"); continue; }
    if (v("Additional Notes") !== null)    { current.additionalNotes = v("Additional Notes"); continue; }
    if (v("Spares Required") !== null)     { current.sparesRequired = v("Spares Required"); continue; }
  }
  saveCurrent();
  return records;
}

function BoilerServiceEmailScreen({ onBack, onHome, onImport, defaultEngData }) {
  const [tab, setTab] = useState("send");
  const [propertyCount, setPropertyCount] = useState(1);
  const [copied, setCopied] = useState(false);
  const [emailText, setEmailText] = useState("");
  const [parsed, setParsed] = useState([]);
  const [parseStatus, setParseStatus] = useState("idle");
  const [parseMsg, setParseMsg] = useState("");

  const BS_EMAIL = "lspapandh@gmail.com";
  const BS_BLUE = "#1a3a8f";

  function buildTemplate() {
    let tmpl = "BOILER SERVICE RECORD REQUEST\n";
    tmpl += "=".repeat(40) + "\n\n";
    tmpl += "Please fill in the details below for each property and send back.\n\n";
    for (let i = 1; i <= propertyCount; i++) {
      tmpl += `PROPERTY ${i}\n`;
      tmpl += "-".repeat(30) + "\n";
      tmpl += "Cert Ref: \n";
      tmpl += "Client Name: \n";
      tmpl += "Client Address 1: \n";
      tmpl += "Client Address 2: \n";
      tmpl += "Client Address 3: \n";
      tmpl += "Client Postcode: \n";
      tmpl += "Client Tel: \n";
      tmpl += "Client Email: \n";
      tmpl += "Install Name: \n";
      tmpl += "Install Address 1: \n";
      tmpl += "Install Address 2: \n";
      tmpl += "Install Postcode: \n";
      tmpl += "Install Tel: \n";
      tmpl += "Work Type Service: (Yes / No / N/A)\n";
      tmpl += "Work Type Breakdown: (Yes / No / N/A)\n";
      tmpl += "Boiler Make: \n";
      tmpl += "Boiler Model: \n";
      tmpl += "Boiler Serial: \n";
      tmpl += "Appliance Make: \n";
      tmpl += "Appliance Model: \n";
      tmpl += "Appliance Serial: \n";
      tmpl += "CO Reading: \n";
      tmpl += "CO2 Reading: \n";
      tmpl += "CO/CO2 Ratio: \n";
      tmpl += "Additional Notes: \n";
      tmpl += "Spares Required: \n";
      tmpl += "\n";
    }
    tmpl += "END OF JOB";
    return tmpl;
  }

  function copyTemplate() {
    navigator.clipboard.writeText(buildTemplate()).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  }

  function openMailto() {
    const body = encodeURIComponent(buildTemplate());
    const subject = encodeURIComponent("Boiler Service Record Request");
    window.open(`mailto:${BS_EMAIL}?subject=${subject}&body=${body}`, "_blank");
  }

  function doParse() {
    if (!emailText.trim()) return;
    setParseStatus("loading");
    try {
      const results = parseBSEmailTemplate(emailText);
      if (!results || results.length === 0) throw new Error("No PROPERTY blocks found. Make sure the email uses the correct template format.");
      setParsed(results);
      setParseStatus("parsed");
      setParseMsg(`Found ${results.length} propert${results.length===1?"y":"ies"} ready to import.`);
    } catch(e) {
      setParseStatus("error");
      setParseMsg("Error: " + e.message);
    }
  }

  function doImport() {
    const now = new Date();
    const savedSig = (() => { try { return localStorage.getItem(sk("gsc_engineer_sig")) || null; } catch(e) { return null; } })();
    const defaultChecks = { flueType:"N/A", ventilationSize:"N/A", waterFuelSound:"N/A", electricallyFused:"N/A", correctValving:"N/A", isolationAvailable:"N/A", boilerPlantroom:"N/A", heatExchanger:"N/A", ignition:"N/A", gasValve:"N/A", fan:"N/A", safetyDevice:"N/A", controlBox:"N/A", burnersAndPilot:"N/A", fuelPressure:"N/A", burnerWashed:"N/A", pilotAssembly:"N/A", ignitionSystem:"N/A", burnerFan:"N/A", heatExchangerFlueways:"N/A", fuelElectrical:"N/A" };
    const newRecords = parsed.map((p, i) => ({
      type: "bs",
      serviceData: {
        ...defaultChecks,
        certRef: p.certRef || ("BS-" + (now.getTime() + i)),
        clientName: p.clientName || "",
        clientAddr1: p.clientAddr1 || "",
        clientAddr2: p.clientAddr2 || "",
        clientAddr3: p.clientAddr3 || "",
        clientPostcode: p.clientPostcode || "",
        clientTel: p.clientTel || "",
        clientEmail: p.clientEmail || "",
        instName: p.instName || p.clientName || "",
        instAddr1: p.instAddr1 || p.clientAddr1 || "",
        instAddr2: p.instAddr2 || p.clientAddr2 || "",
        instAddr3: p.instAddr3 || p.clientAddr3 || "",
        instPostcode: p.instPostcode || p.clientPostcode || "",
        instTel: p.instTel || p.clientTel || "",
        typeOfWorkService: p.typeOfWorkService || "N/A",
        typeOfWorkBreakdown: p.typeOfWorkBreakdown || "N/A",
        boilerMake: p.boilerMake || "",
        boilerModel: p.boilerModel || "",
        boilerSerial: p.boilerSerial || "",
        applianceMake: p.applianceMake || "",
        applianceModel: p.applianceModel || "",
        applianceSerial: p.applianceSerial || "",
        coReading: p.coReading || "",
        co2Reading: p.co2Reading || "",
        coCo2Ratio: p.coCo2Ratio || "",
        additionalNotes: p.additionalNotes || "",
        sparesRequired: p.sparesRequired || "",
        dataProtection: false,
        customerDeclaration: "",
      },
      bsSigData: savedSig ? { engineerSigImage: savedSig } : {},
      bsEngData: { ...defaultEngData },
      savedAt: new Date(now.getTime() + i * 1000).toISOString(),
    }));
    onImport(newRecords);
    alert(`✅ ${newRecords.length} Boiler Service record${newRecords.length===1?"":"s"} created!`);
    onHome();
  }

  const tabStyle = (active) => ({
    flex:1, padding:"11px 0", border:"none", cursor:"pointer", fontWeight:700, fontSize:14,
    fontFamily:"'Segoe UI',sans-serif",
    background: active ? BS_BLUE : "#f0f2f8",
    color: active ? "#fff" : "#666",
    borderRadius: 0,
    transition:"all 0.15s",
  });

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Boiler Service Email" onBack={onBack} onHome={onHome}/>

      <div style={{ display:"flex", flexShrink:0, borderBottom:"2px solid #dde" }}>
        <button style={tabStyle(tab==="send")} onClick={()=>setTab("send")}>📤 Send Template</button>
        <button style={tabStyle(tab==="import")} onClick={()=>setTab("import")}>📥 Import Reply</button>
      </div>

      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>

        {tab === "send" && (
          <div>
            <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:14, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
              <p style={{ fontSize:13, color:"#444", marginBottom:14, lineHeight:1.6 }}>
                Choose how many properties to include, then send the template to <strong>{BS_EMAIL}</strong>. Once filled in and replied, come back to the <em>Import Reply</em> tab.
              </p>
              <label style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:6, display:"block" }}>Number of Properties</label>
              <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:18 }}>
                <button onClick={()=>setPropertyCount(c=>Math.max(1,c-1))} style={{ width:38, height:38, borderRadius:"50%", border:"2px solid #ddd", background:"#f5f5f5", fontSize:20, cursor:"pointer", fontWeight:700 }}>−</button>
                <span style={{ fontSize:24, fontWeight:800, color:BS_BLUE, minWidth:32, textAlign:"center" }}>{propertyCount}</span>
                <button onClick={()=>setPropertyCount(c=>Math.min(20,c+1))} style={{ width:38, height:38, borderRadius:"50%", border:"2px solid #ddd", background:"#f5f5f5", fontSize:20, cursor:"pointer", fontWeight:700 }}>+</button>
              </div>
              <button onClick={openMailto} style={{ width:"100%", background:BS_BLUE, color:"#fff", border:"none", borderRadius:12, padding:"13px", fontSize:15, fontWeight:700, cursor:"pointer", marginBottom:10 }}>
                ✉️ Open in Mail App
              </button>
              <button onClick={copyTemplate} style={{ width:"100%", background:"#fff", color:BS_BLUE, border:`2px solid ${BS_BLUE}`, borderRadius:12, padding:"13px", fontSize:15, fontWeight:700, cursor:"pointer" }}>
                {copied ? "✅ Copied!" : "📋 Copy Template"}
              </button>
            </div>

            <div style={{ background:"#fff", borderRadius:12, padding:14, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
              <p style={{ fontSize:12, fontWeight:700, color:"#888", marginBottom:8, textTransform:"uppercase", letterSpacing:"0.05em" }}>Template Preview</p>
              <pre style={{ fontSize:12, color:"#333", whiteSpace:"pre-wrap", margin:0, fontFamily:"monospace", lineHeight:1.7 }}>{buildTemplate()}</pre>
            </div>
          </div>
        )}

        {tab === "import" && (
          <div>
            <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:14, boxShadow:"0 1px 4px rgba(0,0,0,0.06)", fontSize:13, color:"#444", lineHeight:1.6 }}>
              Paste the completed reply email below and tap <strong>Parse</strong>. A Boiler Service record and PDF will be created for each property automatically.
            </div>

            <textarea
              value={emailText}
              onChange={e=>{ setEmailText(e.target.value); setParseStatus("idle"); setParseMsg(""); }}
              placeholder={"Paste the completed email reply here...\n\nPROPERTY 1\n-----\nCert Ref: BS-001\nClient Name: John Smith\nClient Address 1: 47 High Street\n..."}
              style={{ width:"100%", minHeight:160, borderRadius:10, border:"1px solid #ddd", padding:"10px 12px", fontSize:13, fontFamily:"monospace", resize:"vertical", boxSizing:"border-box", marginBottom:10 }}
            />
            <button onClick={doParse} disabled={!emailText.trim()} style={{ width:"100%", background:"#fff", color:BS_BLUE, border:`2px solid ${BS_BLUE}`, borderRadius:12, padding:"12px", fontSize:14, fontWeight:700, cursor:"pointer", marginBottom:14, opacity:!emailText.trim()?0.5:1 }}>
              Parse Email
            </button>

            {parseMsg && (
              <div style={{ background: parseStatus==="error"?"#fff3f3":parseStatus==="parsed"?"#f0fff4":"#f5f5f5", border:`1px solid ${parseStatus==="error"?"#ffcdd2":parseStatus==="parsed"?"#c8e6c9":"#c5cae9"}`, borderRadius:10, padding:"12px 14px", marginBottom:14, fontSize:13, color: parseStatus==="error"?"#c62828":parseStatus==="parsed"?"#2e7d32":"#1a3a8f" }}>
                {parseMsg}
              </div>
            )}

            {parseStatus==="parsed" && parsed.length > 0 && (
              <div>
                {parsed.map((p, i) => (
                  <div key={i} style={{ border:"1px solid #e0e0e0", borderRadius:10, padding:"12px 14px", marginBottom:10, fontSize:13, background:"#fff" }}>
                    <div style={{ fontWeight:700, color:BS_BLUE, marginBottom:4 }}>Property {i+1}: {p.clientName || p.clientAddr1 || "—"}</div>
                    <div style={{ color:"#555" }}>Cert Ref: {p.certRef || "—"}</div>
                    <div style={{ color:"#555" }}>Address: {p.clientAddr1 || "—"}</div>
                    {p.boilerMake && <div style={{ color:"#555" }}>Boiler: {p.boilerMake} {p.boilerModel}</div>}
                    {p.coReading && <div style={{ color:"#555" }}>CO: {p.coReading} · CO2: {p.co2Reading}</div>}
                  </div>
                ))}
                <button onClick={doImport} style={{ width:"100%", background:"#2e7d32", color:"#fff", border:"none", borderRadius:12, padding:"15px", fontSize:16, fontWeight:700, cursor:"pointer", marginTop:6 }}>
                  ✅ Create {parsed.length} Boiler Service Record{parsed.length!==1?"s":""}
                </button>
              </div>
            )}
          </div>
        )}

      </div>
    </div>
  );
}

// ─── Email Import Screen ─────────────────────────────────────────────────────
function EmailImportScreen({ onBack, onHome, onImportCerts, defaultEngineerData }) {
  const [status, setStatus] = useState("idle"); // idle | loading | parsed | error
  const [message, setMessage] = useState("");
  const [parsedCerts, setParsedCerts] = useState([]);
  const [emailText, setEmailText] = useState("");

  function parseManualText() {
    if (!emailText.trim()) return;
    setStatus("loading");
    setMessage("Parsing email text...");
    try {
      const certs = parseEmailTemplate(emailText);
      if (!certs || certs.length === 0) throw new Error("No PROPERTY blocks found. Make sure your email uses the template format.");
      setParsedCerts(certs);
      setStatus("parsed");
      setMessage("Found " + certs.length + " propert" + (certs.length===1?"y":"ies") + " ready to import.");
    } catch(e) {
      setStatus("error");
      setMessage("Error: " + e.message);
    }
  }

  async function doImport() {
    const now = new Date();
    const newRecords = parsedCerts.map((cert, i) => ({
      certData: {
        certRef: cert.certRef || ("GSC-" + (now.getTime() + i)),
        clientName: cert.clientName || "",
        clientAddr1: cert.clientAddr1 || "",
        clientAddr2: cert.clientAddr2 || "",
        clientAddr3: cert.clientAddr3 || "",
        clientPostcode: cert.clientPostcode || "",
        clientTel: cert.clientTel || "",
        clientEmail: cert.clientEmail || "",
        instName: cert.instName || cert.clientName || "",
        instAddr1: cert.instAddr1 || cert.clientAddr1 || "",
        instAddr2: cert.instAddr2 || cert.clientAddr2 || "",
        instAddr3: cert.instAddr3 || cert.clientAddr3 || "",
        instPostcode: cert.instPostcode || cert.clientPostcode || "",
        instTel: cert.instTel || cert.clientTel || "",
      },
      appliances: cert.appliances || [],
      faults: cert.faults || [],
      finalChecks: {
        gasTightness: cert.gasTightness || "YES",
        pipeworkVisual: cert.pipeworkVisual || "YES",
        emergencyControl: cert.emergencyControl || "YES",
        bonding: cert.bonding || "YES",
        installationPass: cert.installationPass || "YES",
        coAlarm: cert.coAlarm || "YES",
        smokeAlarm: cert.smokeAlarm || "YES",
        inspectionDate: (() => { const d = new Date(); d.setFullYear(d.getFullYear()+1); return d; })(),
      },
      signatureData: (()=>{ try { const sig=localStorage.getItem(sk("gsc_engineer_sig")); return sig ? {engineerSigImage: sig} : {}; } catch(e){return {};} })(),
      engineerData: { ...defaultEngineerData, certDate: now },
      savedAt: new Date(now.getTime() + i * 1000).toISOString(),
    }));
    onImportCerts(newRecords);
    alert(`✅ ${newRecords.length} certificate${newRecords.length===1?"":"s"} imported to Records!`);
    onHome();
  }

  return (
    <div style={{ minHeight:"100dvh", background:`linear-gradient(160deg,${DARK_BLUE} 0%,${BLUE} 60%,${DARK_BLUE} 100%)`, display:"flex", flexDirection:"column" }}>
      <Header title="Email Import" onBack={onBack}/>
      <div style={{ flex:1, margin:"12px 16px 20px", background:"#fff", borderRadius:20, padding:"20px 18px", overflowY:"auto" }}>

        {/* Instructions */}
        <div style={{ background:LIGHT_BG, borderRadius:12, padding:"14px 16px", marginBottom:16, fontSize:13, color:"#444", lineHeight:1.6 }}>
          <strong style={{ color:BLUE }}>How to import:</strong><br/>
          Open the job email on your phone, copy the full text, paste it below and tap <strong>Parse</strong>. One certificate will be created per property automatically.
        </div>

        {/* Paste email text */}
        <textarea
          value={emailText}
          onChange={e=>setEmailText(e.target.value)}
          placeholder={"Paste email text here...\n\nE.g.:\nPROPERTY 1\nClient: John Smith\nAddress: 47 High Street, CV1 1AA\n..."}
          style={{ width:"100%", minHeight:120, borderRadius:10, border:"1px solid #ddd", padding:"10px 12px", fontSize:13, fontFamily:"monospace", resize:"vertical", boxSizing:"border-box", marginBottom:10 }}
        />
        <button onClick={parseManualText} disabled={status==="loading"||!emailText.trim()} style={{ width:"100%", background:"#fff", color:BLUE, border:`2px solid ${BLUE}`, borderRadius:12, padding:"12px", fontSize:14, fontWeight:700, cursor:"pointer", marginBottom:16, opacity:(!emailText.trim()||status==="loading")?0.5:1 }}>
          Parse Pasted Text
        </button>

        {/* Status message */}
        {message && (
          <div style={{ background: status==="error"?"#fff3f3":status==="parsed"?"#f0fff4":"#f5f5f5", border:`1px solid ${status==="error"?"#ffcdd2":status==="parsed"?"#c8e6c9":"#c5cae9"}`, borderRadius:10, padding:"12px 14px", marginBottom:14, fontSize:13, color: status==="error"?"#c62828":status==="parsed"?"#2e7d32":"#1a3a8f" }}>
            {message}
          </div>
        )}

        {/* Parsed results preview */}
        {status==="parsed" && parsedCerts.length > 0 && (
          <div>
            {parsedCerts.map((cert, i) => (
              <div key={i} style={{ border:"1px solid #e0e0e0", borderRadius:10, padding:"12px 14px", marginBottom:10, fontSize:13 }}>
                <div style={{ fontWeight:700, color:BLUE, marginBottom:4 }}>Property {i+1}: {cert.instAddr1||cert.clientAddr1||"—"}</div>
                <div style={{ color:"#555" }}>Client: {cert.clientName||"—"}</div>
                <div style={{ color:"#555" }}>Appliances: {cert.appliances?.length||0}</div>
                {cert.faults?.length>0 && <div style={{ color:"#c62828" }}>Faults: {cert.faults.length}</div>}
              </div>
            ))}
            <button onClick={doImport} style={{ width:"100%", background:"#2e7d32", color:"#fff", border:"none", borderRadius:12, padding:"15px", fontSize:16, fontWeight:700, cursor:"pointer", marginTop:6 }}>
              ✅ Import {parsedCerts.length} Certificate{parsedCerts.length!==1?"s":""} to Records
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

