  const inp = { width:"100%", boxSizing:"border-box", padding:"10px 13px", border:"1.5px solid #e5e7eb", borderRadius:8, fontSize:14, color:"#1a1a2e", background:"#fafafa", fontFamily:"'Segoe UI',sans-serif", outline:"none" };
