// ─── Helper: check if user needs onboarding plan selection ───────────────────
function userNeedsPlanSelection(user) {
  // NEVER block new users — let them use the full app during their 7-day free trial.
  // The PaywallScreen inside App already handles the expired-trial gate.
  return false;
}

function AppWithAuth() {
  const [authed, setAuthed] = useState(() => !!getCurrentUser());
  // "landing" | "login" | "profileSetup"
  const [screen, setScreen] = useState(
    window.location.hash === "#signin" ? "login" :
    window.location.hash === "#register" ? "profileSetup" :
    "landing"
  );
  const [showInstallPrompt, setShowInstallPrompt] = useState(false);
  const [showPlanSelection, setShowPlanSelection] = useState(false);
  const [showContactImport, setShowContactImport] = useState(false);

  // On mount: check Stripe subscription for existing sessions (background, non-blocking)
  useEffect(() => {
    const u = getCurrentUser();
    if (u?.username && !USERS.some(x => x.username === u.username)) {
      checkStripeSubscription(u.username).catch(() => {});
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  function handleLogin(user) {
    setCurrentUser(user);
    setAuthed(true);
    // Request persistent storage so the browser won't evict localStorage data
    if (navigator.storage && navigator.storage.persist) {
      navigator.storage.persist().catch(() => {});
    }
    // Check Stripe subscription status in background (auto-unlocks if active)
    if (user?.username && !USERS.some(u => u.username === user.username)) {
      checkStripeSubscription(user.username).catch(() => {});
    }
    // Supabase: pull cloud data, merge with local, and auto-create profile if needed
    if (isSupabaseEnabled() && user?.isSupabaseUser) {
      (async () => {
        try {
          // Pull cloud data and merge with local storage
          const cloudData = await pullAll();
          if (cloudData) {
            // Merge records
            const localRecords = (() => { try { return JSON.parse(localStorage.getItem(`${user.username}_records`) || "[]"); } catch { return []; } })();
            const merged = mergeRecords(localRecords, cloudData.records || []);
            if (merged.length) { try { localStorage.setItem(`${user.username}_records`, JSON.stringify(merged)); } catch {} }

            // Merge contacts
            if (cloudData.contacts?.length) {
              const localContacts = (() => { try { return JSON.parse(localStorage.getItem(`${user.username}_contacts`) || "[]"); } catch { return []; } })();
              const mergedContacts = mergeRecords(localContacts, cloudData.contacts);
              try { localStorage.setItem(`${user.username}_contacts`, JSON.stringify(mergedContacts)); } catch {}
            }

            // If cloud has a profile, merge it
            if (cloudData.profile) {
              const localProfile = (() => { try { return JSON.parse(localStorage.getItem(`${user.username}_user_profile`) || "{}"); } catch { return {}; } })();
              const mergedProfile = { ...cloudData.profile, ...localProfile };
              try { localStorage.setItem(`${user.username}_user_profile`, JSON.stringify(mergedProfile)); } catch {}
            }
          }

          // Auto-create Supabase profile if none exists on cloud
          const localProfile = (() => { try { return JSON.parse(localStorage.getItem(`${user.username}_user_profile`) || "{}"); } catch { return {}; } })();
          if (localProfile.engineerName || localProfile.companyName) {
            pushProfile({ ...localProfile, username: user.username }).catch(() => {});
          }
        } catch (e) {
          console.warn("[Auth] Post-login sync failed:", e.message);
        }
      })();
    }
  }

  async function handleLogout() {
    // Sign out of Supabase if enabled
    if (isSupabaseEnabled()) {
      try { await supabaseSignOut(); } catch (e) { console.warn("[Auth] Supabase signOut error:", e.message); }
    }
    setCurrentUser(null);
    setAuthed(false);
    setScreen("landing");
  }

  // Install prompt modal overlay (shown once after registration)
  if (authed && showInstallPrompt) {
    return (
      <>
        <App onLogout={handleLogout}/>
        <InstallPromptModal onDismiss={() => {
          try { localStorage.setItem("installPromptShown", "true"); } catch {}
          setShowInstallPrompt(false);
          // After install prompt, skip plan selection — go straight to contact import
          setShowContactImport(true);
        }}/>
      </>
    );
  }

  // Onboarding plan selection (after install prompt)
  if (authed && showPlanSelection) {
    const u = getCurrentUser();
    return <OnboardingPlanScreen currentUser={u} onPlanSelected={() => {
      setShowPlanSelection(false);
      setShowContactImport(true);
    }}/>;
  }

  // Onboarding contact import (after plan selection)
  if (authed && showContactImport) {
    return <ContactImportScreen onDone={() => setShowContactImport(false)} />;
  }

  if (authed) return <App onLogout={handleLogout}/>;

  if (screen === "login") return <LoginScreen onLogin={handleLogin} onBack={()=>setScreen("landing")}/>;
  if (screen === "profileSetup") return <ProfileSetupScreen
    onSave={(profile, userEntry) => {
      // Set the current user first so sk() works correctly
      setCurrentUser(userEntry);
      // Save the profile under the new user's storage key
      const profileWithDate = { ...profile, registeredAt: new Date().toISOString() };
      try { localStorage.setItem(`${userEntry.username}_user_profile`, JSON.stringify(profileWithDate)); } catch {}
      // Push profile to Supabase if enabled (fire-and-forget)
      if (isSupabaseEnabled() && userEntry.isSupabaseUser) {
        pushProfile({ ...profileWithDate, username: userEntry.username }).catch(() => {});
      }
      // Auto-login — show install prompt if not shown before, then plan selection
      setAuthed(true);
      try {
        if (!localStorage.getItem("installPromptShown")) {
          setShowInstallPrompt(true);
        } else {
          // Install prompt already shown — go straight to contact import (skip plan selection)
          setShowContactImport(true);
        }
      } catch {}
    }}
    onBack={()=>setScreen("landing")}
  />;

  return <LandingScreen onLogin={()=>setScreen("login")} onCreateProfile={()=>setScreen("profileSetup")}/>;
}

export default AppWithAuth;
